INSERT INTO `tasks` (`task_id`, `ml_topic`, `task_type`, `prompt`, `options`, `correct_answer`, `context`, `reward_points`, `difficulty`, `order_index`) VALUES
(1, 'intro', 'mcq', 'Which statement best describes machine learning?', '[\"Identify patterns from data\", \"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Identify patterns from data\"', '{\"concept\": \"Machine Learning\", \"lesson\": \"Machine learning is the process of building systems that learn patterns from data instead of being given every rule by hand. In a traditional program, a developer writes explicit instructions for every case. In machine learning, the developer provides examples, chooses a target, and lets the model discover useful relationships between inputs and outputs.\\n\\nThis matters because many real-world problems are too messy for fixed rules alone. Traffic flow, fraud detection, recommendation systems, and image recognition all involve patterns that change over time and are difficult to hard-code.\\n\\nA good mental model is this: machine learning does not “think” like a person. It detects statistical regularities in examples. That is why the quality of the data, the choice of features, and the way the model is evaluated all matter.\\n\\nA common mistake is assuming machine learning guarantees perfect predictions. In reality, it produces estimates based on patterns, uncertainty, and the information it was trained on.\", \"explanation\": \"Machine Learning helps a learner understand how models identify patterns from data.\", \"city_example\": \"In the project, forecasting traffic demand is a useful smart-city example of machine learning.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse machine learning with a related term, so focus on its exact role.\"}', 50, 'easy', 1),
(2, 'supervised', 'mcq', 'A city team wants to training on labelled service requests. Which ML idea fits this best?', '[\"A spreadsheet colour change\", \"Learn from labelled examples\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Learn from labelled examples\"', '{\"concept\": \"Supervised Learning\", \"lesson\": \"Supervised learning is a type of machine learning where the training data includes both inputs and the correct answers, called labels. The model learns a relationship between the input features and the known target so that it can later make predictions on new, unseen examples.\\n\\nThere are two main supervised tasks. Classification predicts categories, such as spam or not spam. Regression predicts continuous values, such as house price or travel time.\\n\\nSupervised learning is powerful because it gives the model feedback during training: it can compare its prediction with the real answer and gradually improve. This is why labelled data is so valuable.\\n\\nIn practice, supervised learning is used in areas like credit scoring, disease prediction, customer support routing, and demand forecasting.\\n\\nA common mistake is to think the model truly understands the labels. It does not. It is learning patterns that correlate with those labels, which means biased labels or poor-quality examples can lead to poor predictions.\", \"explanation\": \"Supervised Learning helps a learner understand how models learn from labelled examples.\", \"city_example\": \"In the project, training on labelled service requests is a useful smart-city example of supervised learning.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse supervised learning with a related term, so focus on its exact role.\"}', 50, 'easy', 2),
(3, 'unsupervised', 'mcq', 'Why is unsupervised learning useful in machine learning?', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"Find structure without labels\", \"It only matters for file storage\"]', '\"Find structure without labels\"', '{\"concept\": \"Unsupervised Learning\", \"lesson\": \"Unsupervised learning is used when data does not come with correct answers or labels. Instead of being told what the output should be, the model tries to discover structure on its own, such as groups, patterns, similarities, or compressed representations.\\n\\nTypical unsupervised tasks include clustering, where similar items are grouped together, and dimensionality reduction, where complex data is simplified while preserving important information.\\n\\nThis is useful when labelled data is expensive, unavailable, or impossible to define clearly. For example, a city might group neighbourhoods by travel behaviour before deciding how to target services.\\n\\nA helpful way to think about unsupervised learning is that the model is organising data rather than predicting a teacher-provided answer.\\n\\nA common mistake is assuming the groups found by the model automatically have a meaningful real-world interpretation. They may reveal structure, but humans still need to decide whether that structure is useful and valid.\", \"explanation\": \"Unsupervised Learning helps a learner understand how models find structure without labels.\", \"city_example\": \"In the project, grouping neighbourhoods by travel pattern is a useful smart-city example of unsupervised learning.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse unsupervised learning with a related term, so focus on its exact role.\"}', 50, 'easy', 3),
(4, 'classification', 'mcq', 'Which option is the clearest example of classification?', '[\"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\", \"Predict categories\"]', '\"Predict categories\"', '{\"concept\": \"Classification\", \"lesson\": \"Classification is a supervised learning task where the model predicts which category an example belongs to. The output is a label such as “spam”, “not spam”, “fraud”, “safe”, or “at risk”.\\n\\nThe model learns from labelled examples and tries to separate classes based on patterns in the input features. Some classification problems involve two classes, called binary classification, while others involve many classes.\\n\\nClassification matters because many important decisions are categorical. A system may need to decide whether a road hazard alert should be triggered, whether a medical image looks suspicious, or which type of customer issue has been submitted.\\n\\nWhen designing a classification system, it is important to think beyond simple correctness. Some mistakes are more serious than others, which is why metrics like precision and recall matter.\\n\\nA common mistake is confusing classification with regression. If the target is a category, it is classification. If the target is a number, it is regression.\", \"explanation\": \"Classification helps a learner understand how models predict categories.\", \"city_example\": \"In the project, predicting urgent or not urgent is a useful smart-city example of classification.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse classification with a related term, so focus on its exact role.\"}', 50, 'easy', 4),
(5, 'regression', 'mcq', 'If a learner understands regression, what should they know first?', '[\"Predict continuous numbers\", \"That every model must be perfect\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Predict continuous numbers\"', '{\"concept\": \"Regression\", \"lesson\": \"Regression is a supervised learning task where the model predicts a continuous numerical value rather than a category. Typical examples include house prices, energy usage, travel time, temperature, or expected demand.\\n\\nThe goal of regression is to estimate how changes in the input features relate to changes in the target value. A model learns from past examples and then produces a numeric prediction for new inputs.\\n\\nRegression matters because many real-world planning and forecasting problems require estimates, not labels. A smart-city system might predict tomorrow’s traffic volume or estimate the energy load for a district.\\n\\nA useful way to think about regression is that the model is drawing a relationship between variables and using that relationship to predict a number.\\n\\nA common mistake is using regression when the outcome is actually a category. If you are predicting “yes or no”, that is not a regression problem even if the answer can be written as 0 or 1.\", \"explanation\": \"Regression helps a learner understand how models predict continuous numbers.\", \"city_example\": \"In the project, predicting daily energy demand is a useful smart-city example of regression.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse regression with a related term, so focus on its exact role.\"}', 50, 'easy', 5),
(6, 'features', 'mcq', 'Which statement best describes features?', '[\"It means manually writing every rule by hand\", \"Act as inputs to a model\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Act as inputs to a model\"', '{\"concept\": \"Features\", \"lesson\": \"Features are the input variables the model uses to make predictions. They are the pieces of information that describe each example, such as age, income, distance travelled, temperature, or number of past complaints.\\n\\nFeature quality is one of the biggest influences on model performance. Useful features contain signal that relates to the target. Poor features add noise, create confusion, or encourage overfitting.\\n\\nChoosing features is not just a technical step; it is a design decision. You must think about what information would realistically be available at prediction time and whether each feature has a sensible relationship to the outcome.\\n\\nIn practice, strong machine learning projects often succeed because the features are thoughtful and relevant, not just because the algorithm is advanced.\\n\\nA common mistake is assuming more features always lead to better performance. Extra features can make the model slower, harder to interpret, and more likely to learn irrelevant patterns.\", \"explanation\": \"Features helps a learner understand how models act as inputs to a model.\", \"city_example\": \"In the project, using rainfall and time of day is a useful smart-city example of features.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse features with a related term, so focus on its exact role.\"}', 50, 'easy', 6),
(7, 'labels', 'mcq', 'A city team wants to marking a road as dangerous. Which ML idea fits this best?', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"Act as the correct answer during training\", \"A badge counter only\"]', '\"Act as the correct answer during training\"', '{\"concept\": \"Labels\", \"lesson\": \"Labels are the correct answers attached to training examples in supervised learning. They tell the model what it is supposed to learn to predict. For example, a label might be “spam”, “flood risk”, “high demand”, or a numeric target such as energy cost.\\n\\nLabels matter because they shape the entire learning task. If the labels are incorrect, inconsistent, biased, or poorly defined, the model will learn the wrong lesson even if the code is technically correct.\\n\\nGood labels should be clear, meaningful, and aligned with the real-world decision the system is meant to support. If different people would label the same example differently, that inconsistency can reduce model quality.\\n\\nA common mistake is treating labels as objective truth in every case. In many real-world systems, labels are created by humans or by imperfect past processes, so they can reflect human error, bias, or missing context.\", \"explanation\": \"Labels helps a learner understand how models act as the correct answer during training.\", \"city_example\": \"In the project, marking a road as dangerous is a useful smart-city example of labels.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse labels with a related term, so focus on its exact role.\"}', 50, 'easy', 7),
(8, 'training', 'mcq', 'Why is training useful in machine learning?', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\", \"Fit a model using examples\"]', '\"Fit a model using examples\"', '{\"concept\": \"Training\", \"lesson\": \"Training is the stage where a machine learning model learns from data by adjusting its internal parameters to reduce error. During training, the model repeatedly compares its predictions with the correct answers and updates itself to improve.\\n\\nThe exact mechanism depends on the algorithm, but the general idea is the same: the model is tuned so that it captures useful patterns in the training data.\\n\\nTraining matters because this is where the model’s behaviour is shaped. Choices such as feature selection, preprocessing, hyperparameters, and training data quality all affect what the model learns.\\n\\nA useful mental model is that training is not the same as memorising every example perfectly. Good training should help the model generalise to new data, not just perform well on the examples it has already seen.\\n\\nA common mistake is assuming more training automatically means a better model. Without careful evaluation, extra training can sometimes lead to overfitting.\", \"explanation\": \"Training helps a learner understand how models fit a model using examples.\", \"city_example\": \"In the project, learning from historical bus delay data is a useful smart-city example of training.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse training with a related term, so focus on its exact role.\"}', 50, 'easy', 8),
(9, 'testing', 'mcq', 'Which option is the clearest example of testing?', '[\"Check performance on unseen data\", \"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Check performance on unseen data\"', '{\"concept\": \"Testing\", \"lesson\": \"Testing is the process of evaluating a trained model on data it has not seen during training. This is essential because strong performance on training data alone does not prove that the model will work in real use.\\n\\nThe purpose of testing is to estimate how well the model generalises. If performance drops sharply on the test set, the model may be overfitting, the features may be weak, or the training data may not represent the real problem well.\\n\\nTesting matters because machine learning systems are judged by future performance, not by how well they remember the past. A model used in a city service, for example, must make reliable predictions on new requests and changing conditions.\\n\\nA common mistake is accidentally letting information from the test set influence training. Once that happens, the test result is no longer a fair measure of real-world performance.\", \"explanation\": \"Testing helps a learner understand how models check performance on unseen data.\", \"city_example\": \"In the project, checking predictions on future traffic days is a useful smart-city example of testing.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse testing with a related term, so focus on its exact role.\"}', 50, 'easy', 9),
(10, 'train_test', 'mcq', 'If a learner understands a train/test split, what should they know first?', '[\"That every model must be perfect\", \"Separate learning from evaluation\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Separate learning from evaluation\"', '{\"concept\": \"A Train/Test Split\", \"lesson\": \"A train/test split divides the dataset into two parts: one portion for training the model and another for evaluating it. The training set teaches the model, while the test set checks how well it performs on unseen data.\\n\\nThis split matters because machine learning should be judged on generalisation, not memorisation. A model can score very highly on the training data while failing on new examples if it has learned overly specific patterns.\\n\\nA common workflow is to train on the larger portion of the data and reserve a smaller portion for testing. The exact ratio can vary, but the key principle is that the test data must remain separate until evaluation.\\n\\nA common mistake is performing preprocessing on the full dataset before splitting. That leaks information from the test set into training and makes the evaluation overly optimistic.\", \"explanation\": \"A Train/Test Split helps a learner understand how models separate learning from evaluation.\", \"city_example\": \"In the project, holding back unseen examples is a useful smart-city example of a train/test split.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse a train/test split with a related term, so focus on its exact role.\"}', 50, 'easy', 10),
(11, 'accuracy', 'mcq', 'Which statement best describes accuracy?', '[\"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"Measure the proportion of correct predictions\", \"It guarantees perfect predictions\"]', '\"Measure the proportion of correct predictions\"', '{\"concept\": \"Accuracy\", \"lesson\": \"Accuracy measures the proportion of predictions the model got correct out of all predictions made. It is one of the simplest evaluation metrics and is often the first number people look at.\\n\\nAccuracy is useful when classes are balanced and all types of mistakes matter equally. In that setting, it provides an easy summary of overall correctness.\\n\\nHowever, accuracy can be misleading. If 99% of cases are negative, a model that always predicts the majority class can still achieve 99% accuracy while being practically useless.\\n\\nThis is why machine learning evaluation must consider the structure of the problem. For imbalanced or high-risk tasks, metrics like precision, recall, and F1 score are often more informative.\\n\\nA common mistake is treating high accuracy as proof that a model is good without checking class balance, error types, or real-world consequences.\", \"explanation\": \"Accuracy helps a learner understand how models measure the proportion of correct predictions.\", \"city_example\": \"In the project, counting correct service classifications is a useful smart-city example of accuracy.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse accuracy with a related term, so focus on its exact role.\"}', 50, 'easy', 11),
(12, 'overfitting', 'mcq', 'A city team wants to learning old traffic quirks. Which ML idea fits this best?', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"A badge counter only\", \"Memorise training data too closely\"]', '\"Memorise training data too closely\"', '{\"concept\": \"Overfitting\", \"lesson\": \"Overfitting happens when a model learns the training data too closely, including noise, quirks, or accidental patterns that do not generalise to new data. An overfit model often performs very well during training but poorly on unseen examples.\\n\\nThis usually happens when the model is too flexible for the amount or quality of data available, or when it is trained without enough constraints.\\n\\nOverfitting matters because the goal of machine learning is not to remember the training set. The goal is to make reliable predictions in new situations.\\n\\nSigns of overfitting include a large gap between training performance and test performance. Common ways to reduce it include getting more data, simplifying the model, using regularisation, and validating carefully.\\n\\nA common mistake is assuming that a very high training score means the model is excellent. In many cases, it is actually a warning sign.\", \"explanation\": \"Overfitting helps a learner understand how models memorise training data too closely.\", \"city_example\": \"In the project, learning old traffic quirks is a useful smart-city example of overfitting.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse overfitting with a related term, so focus on its exact role.\"}', 50, 'easy', 12),
(13, 'underfitting', 'mcq', 'Why is underfitting useful in machine learning?', '[\"Miss the pattern because the model is too simple\", \"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\"]', '\"Miss the pattern because the model is too simple\"', '{\"concept\": \"Underfitting\", \"lesson\": \"Underfitting happens when a model is too simple to capture the important patterns in the data. As a result, it performs poorly not only on the test set but often on the training set as well.\\n\\nAn underfit model may ignore meaningful relationships because it lacks enough capacity, uses weak features, or has been trained insufficiently.\\n\\nThis matters because a model that is too simple cannot support useful decisions, no matter how carefully it is evaluated. In practice, underfitting can look like consistently low accuracy, high prediction error, or failure to improve even after training.\\n\\nCommon ways to reduce underfitting include using richer features, choosing a more expressive model, tuning hyperparameters, or training for longer when appropriate.\\n\\nA common mistake is focusing only on avoiding overfitting and forgetting that a model can also fail because it has learned too little.\", \"explanation\": \"Underfitting helps a learner understand how models miss the pattern because the model is too simple.\", \"city_example\": \"In the project, using a weak demand model is a useful smart-city example of underfitting.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse underfitting with a related term, so focus on its exact role.\"}', 50, 'easy', 13),
(14, 'preprocessing', 'mcq', 'Which option is the clearest example of preprocessing?', '[\"Renaming a folder\", \"Prepare messy data before modelling\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Prepare messy data before modelling\"', '{\"concept\": \"Preprocessing\", \"lesson\": \"Preprocessing is the stage where raw data is cleaned, transformed, and prepared so that a machine learning model can use it effectively. Real-world data is often incomplete, inconsistent, categorical, poorly scaled, or noisy, so it rarely goes directly into a model unchanged.\\n\\nTypical preprocessing steps include handling missing values, encoding categories, scaling numeric variables, and ensuring formats are consistent. The exact pipeline depends on the data and the algorithm.\\n\\nPreprocessing matters because the model can only learn from the representation it receives. If the input is messy or misleading, even a strong algorithm will struggle.\\n\\nA useful principle is that preprocessing should mirror what is available at prediction time. You should also fit preprocessing steps using only training data, then apply them to validation or test data.\\n\\nA common mistake is treating preprocessing as a minor technical detail. In practice, it is often one of the biggest factors in model quality.\", \"explanation\": \"Preprocessing helps a learner understand how models prepare messy data before modelling.\", \"city_example\": \"In the project, cleaning sensor data is a useful smart-city example of preprocessing.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse preprocessing with a related term, so focus on its exact role.\"}', 50, 'easy', 14),
(15, 'generalisation', 'mcq', 'If a learner understands generalisation, what should they know first?', '[\"That every model must be perfect\", \"That data never changes\", \"Perform well on new unseen cases\", \"That testing is unnecessary\"]', '\"Perform well on new unseen cases\"', '{\"concept\": \"Generalisation\", \"lesson\": \"Generalisation is a model’s ability to perform well on new, unseen data rather than only on the examples used during training. This is the real goal of machine learning, because useful systems must work outside the training set.\\n\\nA model with good generalisation has learned patterns that are broad and meaningful, not just details specific to the training data. Strong evaluation practices, such as train/test splits and cross-validation, are designed to estimate this.\\n\\nGeneralisation matters because real-world data changes across time, place, and context. A city model trained on one period of demand must still perform when future demand shifts.\\n\\nA common mistake is to think training success automatically means generalisation. It does not. Good generalisation depends on representative data, careful evaluation, sensible features, and avoiding leakage and overfitting.\", \"explanation\": \"Generalisation helps a learner understand how models perform well on new unseen cases.\", \"city_example\": \"In the project, predicting tomorrow\'s congestion is a useful smart-city example of generalisation.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse generalisation with a related term, so focus on its exact role.\"}', 50, 'easy', 15),
(16, 'intro', 'mcq', 'Which statement best describes machine learning? (Curriculum step 16)', '[\"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\", \"Identify patterns from data\"]', '\"Identify patterns from data\"', '{\"concept\": \"Machine Learning\", \"lesson\": \"Machine learning is the process of building systems that learn patterns from data instead of being given every rule by hand. In a traditional program, a developer writes explicit instructions for every case. In machine learning, the developer provides examples, chooses a target, and lets the model discover useful relationships between inputs and outputs.\\n\\nThis matters because many real-world problems are too messy for fixed rules alone. Traffic flow, fraud detection, recommendation systems, and image recognition all involve patterns that change over time and are difficult to hard-code.\\n\\nA good mental model is this: machine learning does not “think” like a person. It detects statistical regularities in examples. That is why the quality of the data, the choice of features, and the way the model is evaluated all matter.\\n\\nA common mistake is assuming machine learning guarantees perfect predictions. In reality, it produces estimates based on patterns, uncertainty, and the information it was trained on.\", \"explanation\": \"Machine Learning helps a learner understand how models identify patterns from data.\", \"city_example\": \"In the project, forecasting traffic demand is a useful smart-city example of machine learning.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse machine learning with a related term, so focus on its exact role.\"}', 50, 'easy', 16),
(17, 'supervised', 'mcq', 'A city team wants to training on labelled service requests. Which ML idea fits this best? (Curriculum step 17)', '[\"Learn from labelled examples\", \"A spreadsheet colour change\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Learn from labelled examples\"', '{\"concept\": \"Supervised Learning\", \"lesson\": \"Supervised learning is a type of machine learning where the training data includes both inputs and the correct answers, called labels. The model learns a relationship between the input features and the known target so that it can later make predictions on new, unseen examples.\\n\\nThere are two main supervised tasks. Classification predicts categories, such as spam or not spam. Regression predicts continuous values, such as house price or travel time.\\n\\nSupervised learning is powerful because it gives the model feedback during training: it can compare its prediction with the real answer and gradually improve. This is why labelled data is so valuable.\\n\\nIn practice, supervised learning is used in areas like credit scoring, disease prediction, customer support routing, and demand forecasting.\\n\\nA common mistake is to think the model truly understands the labels. It does not. It is learning patterns that correlate with those labels, which means biased labels or poor-quality examples can lead to poor predictions.\", \"explanation\": \"Supervised Learning helps a learner understand how models learn from labelled examples.\", \"city_example\": \"In the project, training on labelled service requests is a useful smart-city example of supervised learning.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse supervised learning with a related term, so focus on its exact role.\"}', 50, 'easy', 17),
(18, 'unsupervised', 'mcq', 'Why is unsupervised learning useful in machine learning? (Curriculum step 18)', '[\"It removes the need for evaluation\", \"Find structure without labels\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\"]', '\"Find structure without labels\"', '{\"concept\": \"Unsupervised Learning\", \"lesson\": \"Unsupervised learning is used when data does not come with correct answers or labels. Instead of being told what the output should be, the model tries to discover structure on its own, such as groups, patterns, similarities, or compressed representations.\\n\\nTypical unsupervised tasks include clustering, where similar items are grouped together, and dimensionality reduction, where complex data is simplified while preserving important information.\\n\\nThis is useful when labelled data is expensive, unavailable, or impossible to define clearly. For example, a city might group neighbourhoods by travel behaviour before deciding how to target services.\\n\\nA helpful way to think about unsupervised learning is that the model is organising data rather than predicting a teacher-provided answer.\\n\\nA common mistake is assuming the groups found by the model automatically have a meaningful real-world interpretation. They may reveal structure, but humans still need to decide whether that structure is useful and valid.\", \"explanation\": \"Unsupervised Learning helps a learner understand how models find structure without labels.\", \"city_example\": \"In the project, grouping neighbourhoods by travel pattern is a useful smart-city example of unsupervised learning.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse unsupervised learning with a related term, so focus on its exact role.\"}', 50, 'easy', 18),
(19, 'classification', 'mcq', 'Which option is the clearest example of classification? (Curriculum step 19)', '[\"Renaming a folder\", \"Printing a static PDF\", \"Predict categories\", \"Changing a chart title\"]', '\"Predict categories\"', '{\"concept\": \"Classification\", \"lesson\": \"Classification is a supervised learning task where the model predicts which category an example belongs to. The output is a label such as “spam”, “not spam”, “fraud”, “safe”, or “at risk”.\\n\\nThe model learns from labelled examples and tries to separate classes based on patterns in the input features. Some classification problems involve two classes, called binary classification, while others involve many classes.\\n\\nClassification matters because many important decisions are categorical. A system may need to decide whether a road hazard alert should be triggered, whether a medical image looks suspicious, or which type of customer issue has been submitted.\\n\\nWhen designing a classification system, it is important to think beyond simple correctness. Some mistakes are more serious than others, which is why metrics like precision and recall matter.\\n\\nA common mistake is confusing classification with regression. If the target is a category, it is classification. If the target is a number, it is regression.\", \"explanation\": \"Classification helps a learner understand how models predict categories.\", \"city_example\": \"In the project, predicting urgent or not urgent is a useful smart-city example of classification.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse classification with a related term, so focus on its exact role.\"}', 50, 'easy', 19),
(20, 'regression', 'mcq', 'If a learner understands regression, what should they know first? (Curriculum step 20)', '[\"That every model must be perfect\", \"That data never changes\", \"That testing is unnecessary\", \"Predict continuous numbers\"]', '\"Predict continuous numbers\"', '{\"concept\": \"Regression\", \"lesson\": \"Regression is a supervised learning task where the model predicts a continuous numerical value rather than a category. Typical examples include house prices, energy usage, travel time, temperature, or expected demand.\\n\\nThe goal of regression is to estimate how changes in the input features relate to changes in the target value. A model learns from past examples and then produces a numeric prediction for new inputs.\\n\\nRegression matters because many real-world planning and forecasting problems require estimates, not labels. A smart-city system might predict tomorrow’s traffic volume or estimate the energy load for a district.\\n\\nA useful way to think about regression is that the model is drawing a relationship between variables and using that relationship to predict a number.\\n\\nA common mistake is using regression when the outcome is actually a category. If you are predicting “yes or no”, that is not a regression problem even if the answer can be written as 0 or 1.\", \"explanation\": \"Regression helps a learner understand how models predict continuous numbers.\", \"city_example\": \"In the project, predicting daily energy demand is a useful smart-city example of regression.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse regression with a related term, so focus on its exact role.\"}', 50, 'easy', 20),
(21, 'features', 'mcq', 'Which statement best describes features? (Curriculum step 21)', '[\"Act as inputs to a model\", \"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Act as inputs to a model\"', '{\"concept\": \"Features\", \"lesson\": \"Features are the input variables the model uses to make predictions. They are the pieces of information that describe each example, such as age, income, distance travelled, temperature, or number of past complaints.\\n\\nFeature quality is one of the biggest influences on model performance. Useful features contain signal that relates to the target. Poor features add noise, create confusion, or encourage overfitting.\\n\\nChoosing features is not just a technical step; it is a design decision. You must think about what information would realistically be available at prediction time and whether each feature has a sensible relationship to the outcome.\\n\\nIn practice, strong machine learning projects often succeed because the features are thoughtful and relevant, not just because the algorithm is advanced.\\n\\nA common mistake is assuming more features always lead to better performance. Extra features can make the model slower, harder to interpret, and more likely to learn irrelevant patterns.\", \"explanation\": \"Features helps a learner understand how models act as inputs to a model.\", \"city_example\": \"In the project, using rainfall and time of day is a useful smart-city example of features.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse features with a related term, so focus on its exact role.\"}', 50, 'easy', 21),
(22, 'labels', 'mcq', 'A city team wants to marking a road as dangerous. Which ML idea fits this best? (Curriculum step 22)', '[\"A spreadsheet colour change\", \"Act as the correct answer during training\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Act as the correct answer during training\"', '{\"concept\": \"Labels\", \"lesson\": \"Labels are the correct answers attached to training examples in supervised learning. They tell the model what it is supposed to learn to predict. For example, a label might be “spam”, “flood risk”, “high demand”, or a numeric target such as energy cost.\\n\\nLabels matter because they shape the entire learning task. If the labels are incorrect, inconsistent, biased, or poorly defined, the model will learn the wrong lesson even if the code is technically correct.\\n\\nGood labels should be clear, meaningful, and aligned with the real-world decision the system is meant to support. If different people would label the same example differently, that inconsistency can reduce model quality.\\n\\nA common mistake is treating labels as objective truth in every case. In many real-world systems, labels are created by humans or by imperfect past processes, so they can reflect human error, bias, or missing context.\", \"explanation\": \"Labels helps a learner understand how models act as the correct answer during training.\", \"city_example\": \"In the project, marking a road as dangerous is a useful smart-city example of labels.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse labels with a related term, so focus on its exact role.\"}', 50, 'easy', 22),
(23, 'training', 'mcq', 'Why is training useful in machine learning? (Curriculum step 23)', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"Fit a model using examples\", \"It only matters for file storage\"]', '\"Fit a model using examples\"', '{\"concept\": \"Training\", \"lesson\": \"Training is the stage where a machine learning model learns from data by adjusting its internal parameters to reduce error. During training, the model repeatedly compares its predictions with the correct answers and updates itself to improve.\\n\\nThe exact mechanism depends on the algorithm, but the general idea is the same: the model is tuned so that it captures useful patterns in the training data.\\n\\nTraining matters because this is where the model’s behaviour is shaped. Choices such as feature selection, preprocessing, hyperparameters, and training data quality all affect what the model learns.\\n\\nA useful mental model is that training is not the same as memorising every example perfectly. Good training should help the model generalise to new data, not just perform well on the examples it has already seen.\\n\\nA common mistake is assuming more training automatically means a better model. Without careful evaluation, extra training can sometimes lead to overfitting.\", \"explanation\": \"Training helps a learner understand how models fit a model using examples.\", \"city_example\": \"In the project, learning from historical bus delay data is a useful smart-city example of training.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse training with a related term, so focus on its exact role.\"}', 50, 'easy', 23),
(24, 'testing', 'mcq', 'Which option is the clearest example of testing? (Curriculum step 24)', '[\"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\", \"Check performance on unseen data\"]', '\"Check performance on unseen data\"', '{\"concept\": \"Testing\", \"lesson\": \"Testing is the process of evaluating a trained model on data it has not seen during training. This is essential because strong performance on training data alone does not prove that the model will work in real use.\\n\\nThe purpose of testing is to estimate how well the model generalises. If performance drops sharply on the test set, the model may be overfitting, the features may be weak, or the training data may not represent the real problem well.\\n\\nTesting matters because machine learning systems are judged by future performance, not by how well they remember the past. A model used in a city service, for example, must make reliable predictions on new requests and changing conditions.\\n\\nA common mistake is accidentally letting information from the test set influence training. Once that happens, the test result is no longer a fair measure of real-world performance.\", \"explanation\": \"Testing helps a learner understand how models check performance on unseen data.\", \"city_example\": \"In the project, checking predictions on future traffic days is a useful smart-city example of testing.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse testing with a related term, so focus on its exact role.\"}', 50, 'easy', 24),
(25, 'train_test', 'mcq', 'If a learner understands a train/test split, what should they know first? (Curriculum step 25)', '[\"Separate learning from evaluation\", \"That every model must be perfect\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Separate learning from evaluation\"', '{\"concept\": \"A Train/Test Split\", \"lesson\": \"A train/test split divides the dataset into two parts: one portion for training the model and another for evaluating it. The training set teaches the model, while the test set checks how well it performs on unseen data.\\n\\nThis split matters because machine learning should be judged on generalisation, not memorisation. A model can score very highly on the training data while failing on new examples if it has learned overly specific patterns.\\n\\nA common workflow is to train on the larger portion of the data and reserve a smaller portion for testing. The exact ratio can vary, but the key principle is that the test data must remain separate until evaluation.\\n\\nA common mistake is performing preprocessing on the full dataset before splitting. That leaks information from the test set into training and makes the evaluation overly optimistic.\", \"explanation\": \"A Train/Test Split helps a learner understand how models separate learning from evaluation.\", \"city_example\": \"In the project, holding back unseen examples is a useful smart-city example of a train/test split.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse a train/test split with a related term, so focus on its exact role.\"}', 50, 'easy', 25),
(26, 'accuracy', 'mcq', 'Which statement best describes accuracy? (Curriculum step 26)', '[\"It means manually writing every rule by hand\", \"Measure the proportion of correct predictions\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Measure the proportion of correct predictions\"', '{\"concept\": \"Accuracy\", \"lesson\": \"Accuracy measures the proportion of predictions the model got correct out of all predictions made. It is one of the simplest evaluation metrics and is often the first number people look at.\\n\\nAccuracy is useful when classes are balanced and all types of mistakes matter equally. In that setting, it provides an easy summary of overall correctness.\\n\\nHowever, accuracy can be misleading. If 99% of cases are negative, a model that always predicts the majority class can still achieve 99% accuracy while being practically useless.\\n\\nThis is why machine learning evaluation must consider the structure of the problem. For imbalanced or high-risk tasks, metrics like precision, recall, and F1 score are often more informative.\\n\\nA common mistake is treating high accuracy as proof that a model is good without checking class balance, error types, or real-world consequences.\", \"explanation\": \"Accuracy helps a learner understand how models measure the proportion of correct predictions.\", \"city_example\": \"In the project, counting correct service classifications is a useful smart-city example of accuracy.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse accuracy with a related term, so focus on its exact role.\"}', 50, 'easy', 26),
(27, 'overfitting', 'mcq', 'A city team wants to learning old traffic quirks. Which ML idea fits this best? (Curriculum step 27)', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"Memorise training data too closely\", \"A badge counter only\"]', '\"Memorise training data too closely\"', '{\"concept\": \"Overfitting\", \"lesson\": \"Overfitting happens when a model learns the training data too closely, including noise, quirks, or accidental patterns that do not generalise to new data. An overfit model often performs very well during training but poorly on unseen examples.\\n\\nThis usually happens when the model is too flexible for the amount or quality of data available, or when it is trained without enough constraints.\\n\\nOverfitting matters because the goal of machine learning is not to remember the training set. The goal is to make reliable predictions in new situations.\\n\\nSigns of overfitting include a large gap between training performance and test performance. Common ways to reduce it include getting more data, simplifying the model, using regularisation, and validating carefully.\\n\\nA common mistake is assuming that a very high training score means the model is excellent. In many cases, it is actually a warning sign.\", \"explanation\": \"Overfitting helps a learner understand how models memorise training data too closely.\", \"city_example\": \"In the project, learning old traffic quirks is a useful smart-city example of overfitting.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse overfitting with a related term, so focus on its exact role.\"}', 50, 'easy', 27);
INSERT INTO `tasks` (`task_id`, `ml_topic`, `task_type`, `prompt`, `options`, `correct_answer`, `context`, `reward_points`, `difficulty`, `order_index`) VALUES
(28, 'underfitting', 'mcq', 'Why is underfitting useful in machine learning? (Curriculum step 28)', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\", \"Miss the pattern because the model is too simple\"]', '\"Miss the pattern because the model is too simple\"', '{\"concept\": \"Underfitting\", \"lesson\": \"Underfitting happens when a model is too simple to capture the important patterns in the data. As a result, it performs poorly not only on the test set but often on the training set as well.\\n\\nAn underfit model may ignore meaningful relationships because it lacks enough capacity, uses weak features, or has been trained insufficiently.\\n\\nThis matters because a model that is too simple cannot support useful decisions, no matter how carefully it is evaluated. In practice, underfitting can look like consistently low accuracy, high prediction error, or failure to improve even after training.\\n\\nCommon ways to reduce underfitting include using richer features, choosing a more expressive model, tuning hyperparameters, or training for longer when appropriate.\\n\\nA common mistake is focusing only on avoiding overfitting and forgetting that a model can also fail because it has learned too little.\", \"explanation\": \"Underfitting helps a learner understand how models miss the pattern because the model is too simple.\", \"city_example\": \"In the project, using a weak demand model is a useful smart-city example of underfitting.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse underfitting with a related term, so focus on its exact role.\"}', 50, 'easy', 28),
(29, 'preprocessing', 'mcq', 'Which option is the clearest example of preprocessing? (Curriculum step 29)', '[\"Prepare messy data before modelling\", \"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Prepare messy data before modelling\"', '{\"concept\": \"Preprocessing\", \"lesson\": \"Preprocessing is the stage where raw data is cleaned, transformed, and prepared so that a machine learning model can use it effectively. Real-world data is often incomplete, inconsistent, categorical, poorly scaled, or noisy, so it rarely goes directly into a model unchanged.\\n\\nTypical preprocessing steps include handling missing values, encoding categories, scaling numeric variables, and ensuring formats are consistent. The exact pipeline depends on the data and the algorithm.\\n\\nPreprocessing matters because the model can only learn from the representation it receives. If the input is messy or misleading, even a strong algorithm will struggle.\\n\\nA useful principle is that preprocessing should mirror what is available at prediction time. You should also fit preprocessing steps using only training data, then apply them to validation or test data.\\n\\nA common mistake is treating preprocessing as a minor technical detail. In practice, it is often one of the biggest factors in model quality.\", \"explanation\": \"Preprocessing helps a learner understand how models prepare messy data before modelling.\", \"city_example\": \"In the project, cleaning sensor data is a useful smart-city example of preprocessing.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse preprocessing with a related term, so focus on its exact role.\"}', 50, 'easy', 29),
(30, 'generalisation', 'mcq', 'If a learner understands generalisation, what should they know first? (Curriculum step 30)', '[\"That every model must be perfect\", \"Perform well on new unseen cases\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Perform well on new unseen cases\"', '{\"concept\": \"Generalisation\", \"lesson\": \"Generalisation is a model’s ability to perform well on new, unseen data rather than only on the examples used during training. This is the real goal of machine learning, because useful systems must work outside the training set.\\n\\nA model with good generalisation has learned patterns that are broad and meaningful, not just details specific to the training data. Strong evaluation practices, such as train/test splits and cross-validation, are designed to estimate this.\\n\\nGeneralisation matters because real-world data changes across time, place, and context. A city model trained on one period of demand must still perform when future demand shifts.\\n\\nA common mistake is to think training success automatically means generalisation. It does not. Good generalisation depends on representative data, careful evaluation, sensible features, and avoiding leakage and overfitting.\", \"explanation\": \"Generalisation helps a learner understand how models perform well on new unseen cases.\", \"city_example\": \"In the project, predicting tomorrow\'s congestion is a useful smart-city example of generalisation.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse generalisation with a related term, so focus on its exact role.\"}', 50, 'easy', 30),
(31, 'intro', 'mcq', 'Which statement best describes machine learning? (Curriculum step 31)', '[\"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"Identify patterns from data\", \"It guarantees perfect predictions\"]', '\"Identify patterns from data\"', '{\"concept\": \"Machine Learning\", \"lesson\": \"Machine learning is the process of building systems that learn patterns from data instead of being given every rule by hand. In a traditional program, a developer writes explicit instructions for every case. In machine learning, the developer provides examples, chooses a target, and lets the model discover useful relationships between inputs and outputs.\\n\\nThis matters because many real-world problems are too messy for fixed rules alone. Traffic flow, fraud detection, recommendation systems, and image recognition all involve patterns that change over time and are difficult to hard-code.\\n\\nA good mental model is this: machine learning does not “think” like a person. It detects statistical regularities in examples. That is why the quality of the data, the choice of features, and the way the model is evaluated all matter.\\n\\nA common mistake is assuming machine learning guarantees perfect predictions. In reality, it produces estimates based on patterns, uncertainty, and the information it was trained on.\", \"explanation\": \"Machine Learning helps a learner understand how models identify patterns from data.\", \"city_example\": \"In the project, forecasting traffic demand is a useful smart-city example of machine learning.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse machine learning with a related term, so focus on its exact role.\"}', 50, 'easy', 31),
(32, 'supervised', 'mcq', 'A city team wants to training on labelled service requests. Which ML idea fits this best? (Curriculum step 32)', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"A badge counter only\", \"Learn from labelled examples\"]', '\"Learn from labelled examples\"', '{\"concept\": \"Supervised Learning\", \"lesson\": \"Supervised learning is a type of machine learning where the training data includes both inputs and the correct answers, called labels. The model learns a relationship between the input features and the known target so that it can later make predictions on new, unseen examples.\\n\\nThere are two main supervised tasks. Classification predicts categories, such as spam or not spam. Regression predicts continuous values, such as house price or travel time.\\n\\nSupervised learning is powerful because it gives the model feedback during training: it can compare its prediction with the real answer and gradually improve. This is why labelled data is so valuable.\\n\\nIn practice, supervised learning is used in areas like credit scoring, disease prediction, customer support routing, and demand forecasting.\\n\\nA common mistake is to think the model truly understands the labels. It does not. It is learning patterns that correlate with those labels, which means biased labels or poor-quality examples can lead to poor predictions.\", \"explanation\": \"Supervised Learning helps a learner understand how models learn from labelled examples.\", \"city_example\": \"In the project, training on labelled service requests is a useful smart-city example of supervised learning.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse supervised learning with a related term, so focus on its exact role.\"}', 50, 'easy', 32),
(33, 'unsupervised', 'mcq', 'Why is unsupervised learning useful in machine learning? (Curriculum step 33)', '[\"Find structure without labels\", \"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\"]', '\"Find structure without labels\"', '{\"concept\": \"Unsupervised Learning\", \"lesson\": \"Unsupervised learning is used when data does not come with correct answers or labels. Instead of being told what the output should be, the model tries to discover structure on its own, such as groups, patterns, similarities, or compressed representations.\\n\\nTypical unsupervised tasks include clustering, where similar items are grouped together, and dimensionality reduction, where complex data is simplified while preserving important information.\\n\\nThis is useful when labelled data is expensive, unavailable, or impossible to define clearly. For example, a city might group neighbourhoods by travel behaviour before deciding how to target services.\\n\\nA helpful way to think about unsupervised learning is that the model is organising data rather than predicting a teacher-provided answer.\\n\\nA common mistake is assuming the groups found by the model automatically have a meaningful real-world interpretation. They may reveal structure, but humans still need to decide whether that structure is useful and valid.\", \"explanation\": \"Unsupervised Learning helps a learner understand how models find structure without labels.\", \"city_example\": \"In the project, grouping neighbourhoods by travel pattern is a useful smart-city example of unsupervised learning.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse unsupervised learning with a related term, so focus on its exact role.\"}', 50, 'easy', 33),
(34, 'classification', 'mcq', 'Which option is the clearest example of classification? (Curriculum step 34)', '[\"Renaming a folder\", \"Predict categories\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Predict categories\"', '{\"concept\": \"Classification\", \"lesson\": \"Classification is a supervised learning task where the model predicts which category an example belongs to. The output is a label such as “spam”, “not spam”, “fraud”, “safe”, or “at risk”.\\n\\nThe model learns from labelled examples and tries to separate classes based on patterns in the input features. Some classification problems involve two classes, called binary classification, while others involve many classes.\\n\\nClassification matters because many important decisions are categorical. A system may need to decide whether a road hazard alert should be triggered, whether a medical image looks suspicious, or which type of customer issue has been submitted.\\n\\nWhen designing a classification system, it is important to think beyond simple correctness. Some mistakes are more serious than others, which is why metrics like precision and recall matter.\\n\\nA common mistake is confusing classification with regression. If the target is a category, it is classification. If the target is a number, it is regression.\", \"explanation\": \"Classification helps a learner understand how models predict categories.\", \"city_example\": \"In the project, predicting urgent or not urgent is a useful smart-city example of classification.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse classification with a related term, so focus on its exact role.\"}', 50, 'easy', 34),
(35, 'regression', 'mcq', 'If a learner understands regression, what should they know first? (Curriculum step 35)', '[\"That every model must be perfect\", \"That data never changes\", \"Predict continuous numbers\", \"That testing is unnecessary\"]', '\"Predict continuous numbers\"', '{\"concept\": \"Regression\", \"lesson\": \"Regression is a supervised learning task where the model predicts a continuous numerical value rather than a category. Typical examples include house prices, energy usage, travel time, temperature, or expected demand.\\n\\nThe goal of regression is to estimate how changes in the input features relate to changes in the target value. A model learns from past examples and then produces a numeric prediction for new inputs.\\n\\nRegression matters because many real-world planning and forecasting problems require estimates, not labels. A smart-city system might predict tomorrow’s traffic volume or estimate the energy load for a district.\\n\\nA useful way to think about regression is that the model is drawing a relationship between variables and using that relationship to predict a number.\\n\\nA common mistake is using regression when the outcome is actually a category. If you are predicting “yes or no”, that is not a regression problem even if the answer can be written as 0 or 1.\", \"explanation\": \"Regression helps a learner understand how models predict continuous numbers.\", \"city_example\": \"In the project, predicting daily energy demand is a useful smart-city example of regression.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse regression with a related term, so focus on its exact role.\"}', 50, 'easy', 35),
(36, 'features', 'mcq', 'Which statement best describes features? (Curriculum step 36)', '[\"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\", \"Act as inputs to a model\"]', '\"Act as inputs to a model\"', '{\"concept\": \"Features\", \"lesson\": \"Features are the input variables the model uses to make predictions. They are the pieces of information that describe each example, such as age, income, distance travelled, temperature, or number of past complaints.\\n\\nFeature quality is one of the biggest influences on model performance. Useful features contain signal that relates to the target. Poor features add noise, create confusion, or encourage overfitting.\\n\\nChoosing features is not just a technical step; it is a design decision. You must think about what information would realistically be available at prediction time and whether each feature has a sensible relationship to the outcome.\\n\\nIn practice, strong machine learning projects often succeed because the features are thoughtful and relevant, not just because the algorithm is advanced.\\n\\nA common mistake is assuming more features always lead to better performance. Extra features can make the model slower, harder to interpret, and more likely to learn irrelevant patterns.\", \"explanation\": \"Features helps a learner understand how models act as inputs to a model.\", \"city_example\": \"In the project, using rainfall and time of day is a useful smart-city example of features.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse features with a related term, so focus on its exact role.\"}', 50, 'easy', 36),
(37, 'labels', 'mcq', 'A city team wants to marking a road as dangerous. Which ML idea fits this best? (Curriculum step 37)', '[\"Act as the correct answer during training\", \"A spreadsheet colour change\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Act as the correct answer during training\"', '{\"concept\": \"Labels\", \"lesson\": \"Labels are the correct answers attached to training examples in supervised learning. They tell the model what it is supposed to learn to predict. For example, a label might be “spam”, “flood risk”, “high demand”, or a numeric target such as energy cost.\\n\\nLabels matter because they shape the entire learning task. If the labels are incorrect, inconsistent, biased, or poorly defined, the model will learn the wrong lesson even if the code is technically correct.\\n\\nGood labels should be clear, meaningful, and aligned with the real-world decision the system is meant to support. If different people would label the same example differently, that inconsistency can reduce model quality.\\n\\nA common mistake is treating labels as objective truth in every case. In many real-world systems, labels are created by humans or by imperfect past processes, so they can reflect human error, bias, or missing context.\", \"explanation\": \"Labels helps a learner understand how models act as the correct answer during training.\", \"city_example\": \"In the project, marking a road as dangerous is a useful smart-city example of labels.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse labels with a related term, so focus on its exact role.\"}', 50, 'easy', 37),
(38, 'training', 'mcq', 'Why is training useful in machine learning? (Curriculum step 38)', '[\"It removes the need for evaluation\", \"Fit a model using examples\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\"]', '\"Fit a model using examples\"', '{\"concept\": \"Training\", \"lesson\": \"Training is the stage where a machine learning model learns from data by adjusting its internal parameters to reduce error. During training, the model repeatedly compares its predictions with the correct answers and updates itself to improve.\\n\\nThe exact mechanism depends on the algorithm, but the general idea is the same: the model is tuned so that it captures useful patterns in the training data.\\n\\nTraining matters because this is where the model’s behaviour is shaped. Choices such as feature selection, preprocessing, hyperparameters, and training data quality all affect what the model learns.\\n\\nA useful mental model is that training is not the same as memorising every example perfectly. Good training should help the model generalise to new data, not just perform well on the examples it has already seen.\\n\\nA common mistake is assuming more training automatically means a better model. Without careful evaluation, extra training can sometimes lead to overfitting.\", \"explanation\": \"Training helps a learner understand how models fit a model using examples.\", \"city_example\": \"In the project, learning from historical bus delay data is a useful smart-city example of training.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse training with a related term, so focus on its exact role.\"}', 50, 'easy', 38),
(39, 'testing', 'mcq', 'Which option is the clearest example of testing? (Curriculum step 39)', '[\"Renaming a folder\", \"Printing a static PDF\", \"Check performance on unseen data\", \"Changing a chart title\"]', '\"Check performance on unseen data\"', '{\"concept\": \"Testing\", \"lesson\": \"Testing is the process of evaluating a trained model on data it has not seen during training. This is essential because strong performance on training data alone does not prove that the model will work in real use.\\n\\nThe purpose of testing is to estimate how well the model generalises. If performance drops sharply on the test set, the model may be overfitting, the features may be weak, or the training data may not represent the real problem well.\\n\\nTesting matters because machine learning systems are judged by future performance, not by how well they remember the past. A model used in a city service, for example, must make reliable predictions on new requests and changing conditions.\\n\\nA common mistake is accidentally letting information from the test set influence training. Once that happens, the test result is no longer a fair measure of real-world performance.\", \"explanation\": \"Testing helps a learner understand how models check performance on unseen data.\", \"city_example\": \"In the project, checking predictions on future traffic days is a useful smart-city example of testing.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse testing with a related term, so focus on its exact role.\"}', 50, 'easy', 39),
(40, 'train_test', 'mcq', 'If a learner understands a train/test split, what should they know first? (Curriculum step 40)', '[\"That every model must be perfect\", \"That data never changes\", \"That testing is unnecessary\", \"Separate learning from evaluation\"]', '\"Separate learning from evaluation\"', '{\"concept\": \"A Train/Test Split\", \"lesson\": \"A train/test split divides the dataset into two parts: one portion for training the model and another for evaluating it. The training set teaches the model, while the test set checks how well it performs on unseen data.\\n\\nThis split matters because machine learning should be judged on generalisation, not memorisation. A model can score very highly on the training data while failing on new examples if it has learned overly specific patterns.\\n\\nA common workflow is to train on the larger portion of the data and reserve a smaller portion for testing. The exact ratio can vary, but the key principle is that the test data must remain separate until evaluation.\\n\\nA common mistake is performing preprocessing on the full dataset before splitting. That leaks information from the test set into training and makes the evaluation overly optimistic.\", \"explanation\": \"A Train/Test Split helps a learner understand how models separate learning from evaluation.\", \"city_example\": \"In the project, holding back unseen examples is a useful smart-city example of a train/test split.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse a train/test split with a related term, so focus on its exact role.\"}', 50, 'easy', 40),
(41, 'accuracy', 'mcq', 'Which statement best describes accuracy? (Curriculum step 41)', '[\"Measure the proportion of correct predictions\", \"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Measure the proportion of correct predictions\"', '{\"concept\": \"Accuracy\", \"lesson\": \"Accuracy measures the proportion of predictions the model got correct out of all predictions made. It is one of the simplest evaluation metrics and is often the first number people look at.\\n\\nAccuracy is useful when classes are balanced and all types of mistakes matter equally. In that setting, it provides an easy summary of overall correctness.\\n\\nHowever, accuracy can be misleading. If 99% of cases are negative, a model that always predicts the majority class can still achieve 99% accuracy while being practically useless.\\n\\nThis is why machine learning evaluation must consider the structure of the problem. For imbalanced or high-risk tasks, metrics like precision, recall, and F1 score are often more informative.\\n\\nA common mistake is treating high accuracy as proof that a model is good without checking class balance, error types, or real-world consequences.\", \"explanation\": \"Accuracy helps a learner understand how models measure the proportion of correct predictions.\", \"city_example\": \"In the project, counting correct service classifications is a useful smart-city example of accuracy.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse accuracy with a related term, so focus on its exact role.\"}', 50, 'easy', 41),
(42, 'overfitting', 'mcq', 'A city team wants to learning old traffic quirks. Which ML idea fits this best? (Curriculum step 42)', '[\"A spreadsheet colour change\", \"Memorise training data too closely\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Memorise training data too closely\"', '{\"concept\": \"Overfitting\", \"lesson\": \"Overfitting happens when a model learns the training data too closely, including noise, quirks, or accidental patterns that do not generalise to new data. An overfit model often performs very well during training but poorly on unseen examples.\\n\\nThis usually happens when the model is too flexible for the amount or quality of data available, or when it is trained without enough constraints.\\n\\nOverfitting matters because the goal of machine learning is not to remember the training set. The goal is to make reliable predictions in new situations.\\n\\nSigns of overfitting include a large gap between training performance and test performance. Common ways to reduce it include getting more data, simplifying the model, using regularisation, and validating carefully.\\n\\nA common mistake is assuming that a very high training score means the model is excellent. In many cases, it is actually a warning sign.\", \"explanation\": \"Overfitting helps a learner understand how models memorise training data too closely.\", \"city_example\": \"In the project, learning old traffic quirks is a useful smart-city example of overfitting.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse overfitting with a related term, so focus on its exact role.\"}', 50, 'easy', 42),
(43, 'underfitting', 'mcq', 'Why is underfitting useful in machine learning? (Curriculum step 43)', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"Miss the pattern because the model is too simple\", \"It only matters for file storage\"]', '\"Miss the pattern because the model is too simple\"', '{\"concept\": \"Underfitting\", \"lesson\": \"Underfitting happens when a model is too simple to capture the important patterns in the data. As a result, it performs poorly not only on the test set but often on the training set as well.\\n\\nAn underfit model may ignore meaningful relationships because it lacks enough capacity, uses weak features, or has been trained insufficiently.\\n\\nThis matters because a model that is too simple cannot support useful decisions, no matter how carefully it is evaluated. In practice, underfitting can look like consistently low accuracy, high prediction error, or failure to improve even after training.\\n\\nCommon ways to reduce underfitting include using richer features, choosing a more expressive model, tuning hyperparameters, or training for longer when appropriate.\\n\\nA common mistake is focusing only on avoiding overfitting and forgetting that a model can also fail because it has learned too little.\", \"explanation\": \"Underfitting helps a learner understand how models miss the pattern because the model is too simple.\", \"city_example\": \"In the project, using a weak demand model is a useful smart-city example of underfitting.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse underfitting with a related term, so focus on its exact role.\"}', 50, 'easy', 43),
(44, 'preprocessing', 'mcq', 'Which option is the clearest example of preprocessing? (Curriculum step 44)', '[\"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\", \"Prepare messy data before modelling\"]', '\"Prepare messy data before modelling\"', '{\"concept\": \"Preprocessing\", \"lesson\": \"Preprocessing is the stage where raw data is cleaned, transformed, and prepared so that a machine learning model can use it effectively. Real-world data is often incomplete, inconsistent, categorical, poorly scaled, or noisy, so it rarely goes directly into a model unchanged.\\n\\nTypical preprocessing steps include handling missing values, encoding categories, scaling numeric variables, and ensuring formats are consistent. The exact pipeline depends on the data and the algorithm.\\n\\nPreprocessing matters because the model can only learn from the representation it receives. If the input is messy or misleading, even a strong algorithm will struggle.\\n\\nA useful principle is that preprocessing should mirror what is available at prediction time. You should also fit preprocessing steps using only training data, then apply them to validation or test data.\\n\\nA common mistake is treating preprocessing as a minor technical detail. In practice, it is often one of the biggest factors in model quality.\", \"explanation\": \"Preprocessing helps a learner understand how models prepare messy data before modelling.\", \"city_example\": \"In the project, cleaning sensor data is a useful smart-city example of preprocessing.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse preprocessing with a related term, so focus on its exact role.\"}', 50, 'easy', 44),
(45, 'generalisation', 'mcq', 'If a learner understands generalisation, what should they know first? (Curriculum step 45)', '[\"Perform well on new unseen cases\", \"That every model must be perfect\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Perform well on new unseen cases\"', '{\"concept\": \"Generalisation\", \"lesson\": \"Generalisation is a model’s ability to perform well on new, unseen data rather than only on the examples used during training. This is the real goal of machine learning, because useful systems must work outside the training set.\\n\\nA model with good generalisation has learned patterns that are broad and meaningful, not just details specific to the training data. Strong evaluation practices, such as train/test splits and cross-validation, are designed to estimate this.\\n\\nGeneralisation matters because real-world data changes across time, place, and context. A city model trained on one period of demand must still perform when future demand shifts.\\n\\nA common mistake is to think training success automatically means generalisation. It does not. Good generalisation depends on representative data, careful evaluation, sensible features, and avoiding leakage and overfitting.\", \"explanation\": \"Generalisation helps a learner understand how models perform well on new unseen cases.\", \"city_example\": \"In the project, predicting tomorrow\'s congestion is a useful smart-city example of generalisation.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse generalisation with a related term, so focus on its exact role.\"}', 50, 'easy', 45),
(46, 'intro', 'mcq', 'Which statement best describes machine learning? (Curriculum step 46)', '[\"It means manually writing every rule by hand\", \"Identify patterns from data\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Identify patterns from data\"', '{\"concept\": \"Machine Learning\", \"lesson\": \"Machine learning is the process of building systems that learn patterns from data instead of being given every rule by hand. In a traditional program, a developer writes explicit instructions for every case. In machine learning, the developer provides examples, chooses a target, and lets the model discover useful relationships between inputs and outputs.\\n\\nThis matters because many real-world problems are too messy for fixed rules alone. Traffic flow, fraud detection, recommendation systems, and image recognition all involve patterns that change over time and are difficult to hard-code.\\n\\nA good mental model is this: machine learning does not “think” like a person. It detects statistical regularities in examples. That is why the quality of the data, the choice of features, and the way the model is evaluated all matter.\\n\\nA common mistake is assuming machine learning guarantees perfect predictions. In reality, it produces estimates based on patterns, uncertainty, and the information it was trained on.\", \"explanation\": \"Machine Learning helps a learner understand how models identify patterns from data.\", \"city_example\": \"In the project, forecasting traffic demand is a useful smart-city example of machine learning.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse machine learning with a related term, so focus on its exact role.\"}', 50, 'easy', 46),
(47, 'supervised', 'mcq', 'A city team wants to training on labelled service requests. Which ML idea fits this best? (Curriculum step 47)', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"Learn from labelled examples\", \"A badge counter only\"]', '\"Learn from labelled examples\"', '{\"concept\": \"Supervised Learning\", \"lesson\": \"Supervised learning is a type of machine learning where the training data includes both inputs and the correct answers, called labels. The model learns a relationship between the input features and the known target so that it can later make predictions on new, unseen examples.\\n\\nThere are two main supervised tasks. Classification predicts categories, such as spam or not spam. Regression predicts continuous values, such as house price or travel time.\\n\\nSupervised learning is powerful because it gives the model feedback during training: it can compare its prediction with the real answer and gradually improve. This is why labelled data is so valuable.\\n\\nIn practice, supervised learning is used in areas like credit scoring, disease prediction, customer support routing, and demand forecasting.\\n\\nA common mistake is to think the model truly understands the labels. It does not. It is learning patterns that correlate with those labels, which means biased labels or poor-quality examples can lead to poor predictions.\", \"explanation\": \"Supervised Learning helps a learner understand how models learn from labelled examples.\", \"city_example\": \"In the project, training on labelled service requests is a useful smart-city example of supervised learning.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse supervised learning with a related term, so focus on its exact role.\"}', 50, 'easy', 47),
(48, 'unsupervised', 'mcq', 'Why is unsupervised learning useful in machine learning? (Curriculum step 48)', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\", \"Find structure without labels\"]', '\"Find structure without labels\"', '{\"concept\": \"Unsupervised Learning\", \"lesson\": \"Unsupervised learning is used when data does not come with correct answers or labels. Instead of being told what the output should be, the model tries to discover structure on its own, such as groups, patterns, similarities, or compressed representations.\\n\\nTypical unsupervised tasks include clustering, where similar items are grouped together, and dimensionality reduction, where complex data is simplified while preserving important information.\\n\\nThis is useful when labelled data is expensive, unavailable, or impossible to define clearly. For example, a city might group neighbourhoods by travel behaviour before deciding how to target services.\\n\\nA helpful way to think about unsupervised learning is that the model is organising data rather than predicting a teacher-provided answer.\\n\\nA common mistake is assuming the groups found by the model automatically have a meaningful real-world interpretation. They may reveal structure, but humans still need to decide whether that structure is useful and valid.\", \"explanation\": \"Unsupervised Learning helps a learner understand how models find structure without labels.\", \"city_example\": \"In the project, grouping neighbourhoods by travel pattern is a useful smart-city example of unsupervised learning.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse unsupervised learning with a related term, so focus on its exact role.\"}', 50, 'easy', 48),
(49, 'classification', 'mcq', 'Which option is the clearest example of classification? (Curriculum step 49)', '[\"Predict categories\", \"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Predict categories\"', '{\"concept\": \"Classification\", \"lesson\": \"Classification is a supervised learning task where the model predicts which category an example belongs to. The output is a label such as “spam”, “not spam”, “fraud”, “safe”, or “at risk”.\\n\\nThe model learns from labelled examples and tries to separate classes based on patterns in the input features. Some classification problems involve two classes, called binary classification, while others involve many classes.\\n\\nClassification matters because many important decisions are categorical. A system may need to decide whether a road hazard alert should be triggered, whether a medical image looks suspicious, or which type of customer issue has been submitted.\\n\\nWhen designing a classification system, it is important to think beyond simple correctness. Some mistakes are more serious than others, which is why metrics like precision and recall matter.\\n\\nA common mistake is confusing classification with regression. If the target is a category, it is classification. If the target is a number, it is regression.\", \"explanation\": \"Classification helps a learner understand how models predict categories.\", \"city_example\": \"In the project, predicting urgent or not urgent is a useful smart-city example of classification.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse classification with a related term, so focus on its exact role.\"}', 50, 'easy', 49),
(50, 'regression', 'mcq', 'If a learner understands regression, what should they know first? (Curriculum step 50)', '[\"That every model must be perfect\", \"Predict continuous numbers\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Predict continuous numbers\"', '{\"concept\": \"Regression\", \"lesson\": \"Regression is a supervised learning task where the model predicts a continuous numerical value rather than a category. Typical examples include house prices, energy usage, travel time, temperature, or expected demand.\\n\\nThe goal of regression is to estimate how changes in the input features relate to changes in the target value. A model learns from past examples and then produces a numeric prediction for new inputs.\\n\\nRegression matters because many real-world planning and forecasting problems require estimates, not labels. A smart-city system might predict tomorrow’s traffic volume or estimate the energy load for a district.\\n\\nA useful way to think about regression is that the model is drawing a relationship between variables and using that relationship to predict a number.\\n\\nA common mistake is using regression when the outcome is actually a category. If you are predicting “yes or no”, that is not a regression problem even if the answer can be written as 0 or 1.\", \"explanation\": \"Regression helps a learner understand how models predict continuous numbers.\", \"city_example\": \"In the project, predicting daily energy demand is a useful smart-city example of regression.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse regression with a related term, so focus on its exact role.\"}', 50, 'easy', 50),
(51, 'confusion_matrix', 'mcq', 'Which statement best describes a confusion matrix?', '[\"Break down actual and predicted classes\", \"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Break down actual and predicted classes\"', '{\"concept\": \"A Confusion Matrix\", \"lesson\": \"A confusion matrix is a table that compares the model’s predicted classes with the actual classes. It breaks results into categories such as true positives, true negatives, false positives, and false negatives.\\n\\nThis matters because overall accuracy can hide important details about what kinds of mistakes the model is making. A confusion matrix shows exactly where the model succeeds and fails.\\n\\nFor example, in a hazard detection task, false negatives may be much more serious than false positives. The confusion matrix helps reveal whether the model is missing dangerous cases or creating too many false alarms.\\n\\nIt is also the foundation for other metrics such as precision, recall, and F1 score.\\n\\nA common mistake is treating the confusion matrix as just another score. It is better understood as a diagnostic tool that explains the structure of the model’s errors.\", \"explanation\": \"A Confusion Matrix helps a learner understand how models break down actual and predicted classes.\", \"city_example\": \"In the project, reviewing hazard alerts is a useful smart-city example of a confusion matrix.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse a confusion matrix with a related term, so focus on its exact role.\"}', 80, 'medium', 1),
(52, 'precision', 'mcq', 'A city team wants to checking inspection flags. Which ML idea fits this best?', '[\"A spreadsheet colour change\", \"Measure how many predicted positives were correct\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Measure how many predicted positives were correct\"', '{\"concept\": \"Precision\", \"lesson\": \"Precision measures how many of the cases predicted as positive were actually positive. In simple terms, it asks: when the model raises an alert, how often is that alert correct?\\n\\nPrecision matters when false positives are costly. For example, if a system flags too many safe situations as risky, it can waste resources, reduce trust, or cause unnecessary disruption.\\n\\nA high-precision model is careful about making positive predictions. That can be valuable in applications like fraud alerts, inspection flags, or targeted interventions where acting on a false alarm has a real cost.\\n\\nHowever, precision alone is not enough. A model can achieve high precision by making very few positive predictions and still miss many real cases.\\n\\nA common mistake is confusing precision with recall. Precision focuses on the correctness of predicted positives, while recall focuses on how many real positives were found.\", \"explanation\": \"Precision helps a learner understand how models measure how many predicted positives were correct.\", \"city_example\": \"In the project, checking inspection flags is a useful smart-city example of precision.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse precision with a related term, so focus on its exact role.\"}', 80, 'medium', 2),
(53, 'recall', 'mcq', 'Why is recall useful in machine learning?', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"Measure how many real positives were found\", \"It only matters for file storage\"]', '\"Measure how many real positives were found\"', '{\"concept\": \"Recall\", \"lesson\": \"Recall measures how many of the actual positive cases the model successfully found. In simple terms, it asks: of all the cases that truly matter, how many did the model catch?\\n\\nRecall matters when missing a positive case is costly. In flood warnings, disease screening, or safety alerts, a false negative can be more harmful than a false positive.\\n\\nA high-recall model is good at finding real positives, even if that sometimes means raising extra false alarms. Whether that trade-off is acceptable depends on the application.\\n\\nRecall should usually be interpreted alongside precision. A system that catches nearly everything but generates many false positives may not be practical.\\n\\nA common mistake is thinking recall means the model is generally accurate. It only tells you how well the model finds positives, not how often its positive predictions are correct.\", \"explanation\": \"Recall helps a learner understand how models measure how many real positives were found.\", \"city_example\": \"In the project, checking flood warnings is a useful smart-city example of recall.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse recall with a related term, so focus on its exact role.\"}', 80, 'medium', 3);
INSERT INTO `tasks` (`task_id`, `ml_topic`, `task_type`, `prompt`, `options`, `correct_answer`, `context`, `reward_points`, `difficulty`, `order_index`) VALUES
(54, 'f1', 'mcq', 'Which option is the clearest example of F1 score?', '[\"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\", \"Balance precision and recall\"]', '\"Balance precision and recall\"', '{\"concept\": \"F1 Score\", \"lesson\": \"F1 score combines precision and recall into a single metric by balancing both. It is especially useful when you need a model that both finds important cases and keeps false alarms under control.\\n\\nThe F1 score is most valuable when classes are imbalanced or when using accuracy alone would hide poor behaviour. It rewards systems that achieve a sensible balance rather than excelling in only one dimension.\\n\\nFor example, a fraud model with perfect precision but very low recall would miss most fraud cases. A model with perfect recall but very low precision would overwhelm investigators with false alerts. F1 helps summarise this trade-off.\\n\\nA common mistake is assuming the F1 score replaces all other metrics. It is useful, but you should still examine precision, recall, and the real-world cost of each type of error.\", \"explanation\": \"F1 Score helps a learner understand how models balance precision and recall.\", \"city_example\": \"In the project, judging rare incident detection is a useful smart-city example of F1 score.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse F1 score with a related term, so focus on its exact role.\"}', 80, 'medium', 4),
(55, 'imbalance', 'mcq', 'If a learner understands class imbalance, what should they know first?', '[\"Describe when one class is much rarer than another\", \"That every model must be perfect\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Describe when one class is much rarer than another\"', '{\"concept\": \"Class Imbalance\", \"lesson\": \"Class imbalance occurs when one class appears much more often than another. For example, fraud cases, severe incidents, or rare equipment failures may represent only a small percentage of the data.\\n\\nThis matters because many models and metrics can look good simply by predicting the majority class most of the time. In an imbalanced dataset, accuracy may be high even when the model is poor at detecting the cases you actually care about.\\n\\nHandling imbalance may involve choosing better metrics, adjusting class weights, resampling the data, or designing the decision threshold carefully.\\n\\nA common mistake is assuming imbalance is a data problem that can be ignored if the overall score looks strong. In practice, imbalance often changes how the entire model should be evaluated and tuned.\", \"explanation\": \"Class Imbalance helps a learner understand how models describe when one class is much rarer than another.\", \"city_example\": \"In the project, modelling fraud cases is a useful smart-city example of class imbalance.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse class imbalance with a related term, so focus on its exact role.\"}', 80, 'medium', 5),
(56, 'scaling', 'mcq', 'Which statement best describes feature scaling?', '[\"It means manually writing every rule by hand\", \"Make numeric features comparable in magnitude\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Make numeric features comparable in magnitude\"', '{\"concept\": \"Feature Scaling\", \"lesson\": \"Feature scaling means adjusting numeric variables so they are on comparable ranges. This is important because some algorithms are sensitive to the size of feature values and may let large-scale variables dominate the learning process.\\n\\nFor example, if one feature ranges from 1 to 10 and another from 1 to 10,000, some distance-based or gradient-based methods can be influenced more by the larger numbers simply because of their scale, not because they are more informative.\\n\\nScaling matters for algorithms such as k-nearest neighbours, support vector machines, and many optimisation-based models.\\n\\nA common mistake is assuming scaling is always required for every algorithm. Tree-based models often need it less, while other methods can be strongly affected.\\n\\nAnother common mistake is fitting the scaler before splitting the data, which can introduce leakage.\", \"explanation\": \"Feature Scaling helps a learner understand how models make numeric features comparable in magnitude.\", \"city_example\": \"In the project, using rainfall and income together is a useful smart-city example of feature scaling.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse feature scaling with a related term, so focus on its exact role.\"}', 80, 'medium', 6),
(57, 'normalisation', 'mcq', 'A city team wants to rescaling sensor readings. Which ML idea fits this best?', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"Rescale values into a standard range\", \"A badge counter only\"]', '\"Rescale values into a standard range\"', '{\"concept\": \"Normalisation\", \"lesson\": \"Normalisation is a type of feature scaling that transforms values to a common range, often between 0 and 1. This can be useful when you want features to be directly comparable in magnitude.\\n\\nIt is especially helpful for algorithms that depend on distances or when the scale of the inputs varies widely. By keeping features within a bounded range, normalisation can stabilise optimisation and reduce the effect of large raw values.\\n\\nNormalisation is different from standardisation. Normalisation focuses on a fixed range, while standardisation centres features around zero and rescales based on spread.\\n\\nA common mistake is using normalisation without thinking about the data distribution or the model type. The best scaling method depends on the problem, not just on habit.\", \"explanation\": \"Normalisation helps a learner understand how models rescale values into a standard range.\", \"city_example\": \"In the project, rescaling sensor readings is a useful smart-city example of normalisation.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse normalisation with a related term, so focus on its exact role.\"}', 80, 'medium', 7),
(58, 'standardisation', 'mcq', 'Why is standardisation useful in machine learning?', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\", \"Transform values to mean 0 and standard deviation 1\"]', '\"Transform values to mean 0 and standard deviation 1\"', '{\"concept\": \"Standardisation\", \"lesson\": \"Standardisation transforms a feature so that it has a mean of zero and a standard deviation of one. This keeps the variable centred and puts it on a comparable scale with other features.\\n\\nStandardisation is widely used because many algorithms work better when features have similar distributions and when optimisation is not dominated by variables with large magnitudes.\\n\\nUnlike normalisation, standardisation does not force data into a fixed range. Instead, it expresses values in terms of how far they are from the mean relative to the spread.\\n\\nThis is often useful for models such as logistic regression, support vector machines, and neural networks.\\n\\nA common mistake is assuming standardisation should be applied before the train/test split. The scaler should be fit on the training data only and then applied to the test data to avoid leakage.\", \"explanation\": \"Standardisation helps a learner understand how models transform values to mean 0 and standard deviation 1.\", \"city_example\": \"In the project, preparing mixed-unit features is a useful smart-city example of standardisation.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse standardisation with a related term, so focus on its exact role.\"}', 80, 'medium', 8),
(59, 'imputation', 'mcq', 'Which option is the clearest example of imputation?', '[\"Fill missing values with sensible estimates\", \"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Fill missing values with sensible estimates\"', '{\"concept\": \"Imputation\", \"lesson\": \"Imputation is the process of filling in missing values rather than simply discarding incomplete rows. Missing data is common in real-world datasets, and handling it carefully can preserve useful information.\\n\\nSimple imputation methods include replacing missing numeric values with the mean or median, or replacing missing categories with the most common value. More advanced methods try to estimate missing values based on other variables.\\n\\nImputation matters because many machine learning algorithms cannot handle missing values directly. The strategy you choose can influence model quality and bias.\\n\\nA common mistake is to remove every row with missing data without considering how much information is being lost. Another mistake is using a poor imputation strategy that distorts the underlying pattern in the data.\", \"explanation\": \"Imputation helps a learner understand how models fill missing values with sensible estimates.\", \"city_example\": \"In the project, repairing weather gaps is a useful smart-city example of imputation.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse imputation with a related term, so focus on its exact role.\"}', 80, 'medium', 9),
(60, 'one_hot', 'mcq', 'If a learner understands one-hot encoding, what should they know first?', '[\"That every model must be perfect\", \"Turn categories into binary columns\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Turn categories into binary columns\"', '{\"concept\": \"One-Hot Encoding\", \"lesson\": \"One-hot encoding is a method for turning categorical values into numeric input that a model can use. Each category becomes its own binary feature, indicating whether that category is present or not.\\n\\nFor example, a feature such as transport mode with values like bus, train, and bike can be converted into separate columns. This avoids implying that one category is “larger” or “smaller” than another when no true order exists.\\n\\nOne-hot encoding matters because many models require numeric input but would misinterpret raw text labels or arbitrary numeric codes.\\n\\nA common mistake is using label-style numeric encoding for categories that have no natural order. That can mislead the model into learning relationships that are not actually meaningful.\", \"explanation\": \"One-Hot Encoding helps a learner understand how models turn categories into binary columns.\", \"city_example\": \"In the project, encoding district names is a useful smart-city example of one-hot encoding.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse one-hot encoding with a related term, so focus on its exact role.\"}', 80, 'medium', 10),
(61, 'feature_engineering', 'mcq', 'Which statement best describes feature engineering?', '[\"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"Create better features from raw data\", \"It guarantees perfect predictions\"]', '\"Create better features from raw data\"', '{\"concept\": \"Feature Engineering\", \"lesson\": \"Feature engineering is the process of creating, transforming, or combining variables so that the model receives more informative input. Rather than only using the raw columns exactly as collected, you design features that better express the underlying problem.\\n\\nExamples include extracting day of week from a date, calculating ratios, grouping rare categories, or turning timestamps into useful behavioural signals.\\n\\nFeature engineering matters because model performance often depends more on the quality of the representation than on the complexity of the algorithm. A well-designed feature can reveal structure that a model would otherwise miss.\\n\\nA common mistake is creating engineered features using information that would not be available at prediction time. That can introduce leakage and make performance look better than it really is.\", \"explanation\": \"Feature Engineering helps a learner understand how models create better features from raw data.\", \"city_example\": \"In the project, extracting hour of day is a useful smart-city example of feature engineering.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse feature engineering with a related term, so focus on its exact role.\"}', 80, 'medium', 11),
(62, 'bias', 'mcq', 'A city team wants to using a very simple demand line. Which ML idea fits this best?', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"A badge counter only\", \"Describe error from oversimplified assumptions\"]', '\"Describe error from oversimplified assumptions\"', '{\"concept\": \"Bias\", \"lesson\": \"In the bias–variance trade-off, bias refers to error caused by overly simple assumptions in the model. A high-bias model is often too rigid to capture important patterns, which can lead to underfitting.\\n\\nBias matters because every model makes assumptions. Some assumptions are useful simplifications, but if they are too strong, the model may miss real relationships in the data.\\n\\nFor example, a very simple model may ignore nonlinear behaviour or interactions between features. This can keep the model stable, but also too limited.\\n\\nA common mistake is confusing this technical meaning of bias with social or ethical bias. Both are important concepts in machine learning, but they refer to different issues and should be understood separately.\", \"explanation\": \"Bias helps a learner understand how models describe error from oversimplified assumptions.\", \"city_example\": \"In the project, using a very simple demand line is a useful smart-city example of bias.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse bias with a related term, so focus on its exact role.\"}', 80, 'medium', 12),
(63, 'variance', 'mcq', 'Why is variance useful in machine learning?', '[\"Describe sensitivity to training-sample changes\", \"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\"]', '\"Describe sensitivity to training-sample changes\"', '{\"concept\": \"Variance\", \"lesson\": \"In the bias–variance trade-off, variance refers to how sensitive a model is to the specific training data it receives. A high-variance model changes a lot when the training set changes and often captures noise as if it were a meaningful pattern.\\n\\nVariance matters because a model with high variance may perform impressively on the training set but fail to generalise. This is one of the main causes of overfitting.\\n\\nComplex models, weak regularisation, and limited training data can all increase variance. Managing variance often involves simplification, more data, better validation, or stronger constraints.\\n\\nA common mistake is thinking model complexity is always beneficial. More flexibility can help, but it also increases the risk that the model learns unstable, non-transferable patterns.\", \"explanation\": \"Variance helps a learner understand how models describe sensitivity to training-sample changes.\", \"city_example\": \"In the project, seeing an unstable route model is a useful smart-city example of variance.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse variance with a related term, so focus on its exact role.\"}', 80, 'medium', 13),
(64, 'cross_validation', 'mcq', 'Which option is the clearest example of cross-validation?', '[\"Renaming a folder\", \"Estimate performance with repeated validation splits\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Estimate performance with repeated validation splits\"', '{\"concept\": \"Cross-Validation\", \"lesson\": \"Cross-validation is an evaluation technique that repeatedly splits the training data into different training and validation portions so that the model can be assessed across multiple runs. This gives a more reliable estimate of performance than relying on a single split alone.\\n\\nIt matters because one train/validation split may be unusually easy or difficult. Cross-validation helps reduce the chance that your judgement of the model depends too heavily on one lucky or unlucky partition.\\n\\nThis is particularly useful when the dataset is not very large, because it allows more efficient use of the available examples.\\n\\nA common mistake is confusing cross-validation with final testing. Cross-validation is often used during model selection and tuning, while the final test set should remain untouched until the end.\", \"explanation\": \"Cross-Validation helps a learner understand how models estimate performance with repeated validation splits.\", \"city_example\": \"In the project, comparing multiple models is a useful smart-city example of cross-validation.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse cross-validation with a related term, so focus on its exact role.\"}', 80, 'medium', 14),
(65, 'leakage', 'mcq', 'If a learner understands data leakage, what should they know first?', '[\"That every model must be perfect\", \"That data never changes\", \"Use information that would not be available in practice\", \"That testing is unnecessary\"]', '\"Use information that would not be available in practice\"', '{\"concept\": \"Data Leakage\", \"lesson\": \"Data leakage happens when information from outside the proper training process influences the model in a way that would not be available in real deployment. This makes the model appear better during evaluation than it truly is.\\n\\nLeakage can occur in many ways: preprocessing on the full dataset before splitting, using future information to create features, or accidentally including variables that reveal the target.\\n\\nLeakage matters because it creates false confidence. A leaked model may look excellent in development and then fail when deployed.\\n\\nA useful rule is this: if the model is learning from information it would not legitimately have at prediction time, something is wrong.\\n\\nA common mistake is thinking leakage only happens in code. It can also be introduced through feature design, data collection, or careless workflow decisions.\", \"explanation\": \"Data Leakage helps a learner understand how models use information that would not be available in practice.\", \"city_example\": \"In the project, accidentally using future demand is a useful smart-city example of data leakage.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse data leakage with a related term, so focus on its exact role.\"}', 80, 'medium', 15),
(66, 'confusion_matrix', 'mcq', 'Which statement best describes a confusion matrix? (Curriculum step 16)', '[\"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\", \"Break down actual and predicted classes\"]', '\"Break down actual and predicted classes\"', '{\"concept\": \"A Confusion Matrix\", \"lesson\": \"A confusion matrix is a table that compares the model’s predicted classes with the actual classes. It breaks results into categories such as true positives, true negatives, false positives, and false negatives.\\n\\nThis matters because overall accuracy can hide important details about what kinds of mistakes the model is making. A confusion matrix shows exactly where the model succeeds and fails.\\n\\nFor example, in a hazard detection task, false negatives may be much more serious than false positives. The confusion matrix helps reveal whether the model is missing dangerous cases or creating too many false alarms.\\n\\nIt is also the foundation for other metrics such as precision, recall, and F1 score.\\n\\nA common mistake is treating the confusion matrix as just another score. It is better understood as a diagnostic tool that explains the structure of the model’s errors.\", \"explanation\": \"A Confusion Matrix helps a learner understand how models break down actual and predicted classes.\", \"city_example\": \"In the project, reviewing hazard alerts is a useful smart-city example of a confusion matrix.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse a confusion matrix with a related term, so focus on its exact role.\"}', 80, 'medium', 16),
(67, 'precision', 'mcq', 'A city team wants to checking inspection flags. Which ML idea fits this best? (Curriculum step 17)', '[\"Measure how many predicted positives were correct\", \"A spreadsheet colour change\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Measure how many predicted positives were correct\"', '{\"concept\": \"Precision\", \"lesson\": \"Precision measures how many of the cases predicted as positive were actually positive. In simple terms, it asks: when the model raises an alert, how often is that alert correct?\\n\\nPrecision matters when false positives are costly. For example, if a system flags too many safe situations as risky, it can waste resources, reduce trust, or cause unnecessary disruption.\\n\\nA high-precision model is careful about making positive predictions. That can be valuable in applications like fraud alerts, inspection flags, or targeted interventions where acting on a false alarm has a real cost.\\n\\nHowever, precision alone is not enough. A model can achieve high precision by making very few positive predictions and still miss many real cases.\\n\\nA common mistake is confusing precision with recall. Precision focuses on the correctness of predicted positives, while recall focuses on how many real positives were found.\", \"explanation\": \"Precision helps a learner understand how models measure how many predicted positives were correct.\", \"city_example\": \"In the project, checking inspection flags is a useful smart-city example of precision.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse precision with a related term, so focus on its exact role.\"}', 80, 'medium', 17),
(68, 'recall', 'mcq', 'Why is recall useful in machine learning? (Curriculum step 18)', '[\"It removes the need for evaluation\", \"Measure how many real positives were found\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\"]', '\"Measure how many real positives were found\"', '{\"concept\": \"Recall\", \"lesson\": \"Recall measures how many of the actual positive cases the model successfully found. In simple terms, it asks: of all the cases that truly matter, how many did the model catch?\\n\\nRecall matters when missing a positive case is costly. In flood warnings, disease screening, or safety alerts, a false negative can be more harmful than a false positive.\\n\\nA high-recall model is good at finding real positives, even if that sometimes means raising extra false alarms. Whether that trade-off is acceptable depends on the application.\\n\\nRecall should usually be interpreted alongside precision. A system that catches nearly everything but generates many false positives may not be practical.\\n\\nA common mistake is thinking recall means the model is generally accurate. It only tells you how well the model finds positives, not how often its positive predictions are correct.\", \"explanation\": \"Recall helps a learner understand how models measure how many real positives were found.\", \"city_example\": \"In the project, checking flood warnings is a useful smart-city example of recall.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse recall with a related term, so focus on its exact role.\"}', 80, 'medium', 18),
(69, 'f1', 'mcq', 'Which option is the clearest example of F1 score? (Curriculum step 19)', '[\"Renaming a folder\", \"Printing a static PDF\", \"Balance precision and recall\", \"Changing a chart title\"]', '\"Balance precision and recall\"', '{\"concept\": \"F1 Score\", \"lesson\": \"F1 score combines precision and recall into a single metric by balancing both. It is especially useful when you need a model that both finds important cases and keeps false alarms under control.\\n\\nThe F1 score is most valuable when classes are imbalanced or when using accuracy alone would hide poor behaviour. It rewards systems that achieve a sensible balance rather than excelling in only one dimension.\\n\\nFor example, a fraud model with perfect precision but very low recall would miss most fraud cases. A model with perfect recall but very low precision would overwhelm investigators with false alerts. F1 helps summarise this trade-off.\\n\\nA common mistake is assuming the F1 score replaces all other metrics. It is useful, but you should still examine precision, recall, and the real-world cost of each type of error.\", \"explanation\": \"F1 Score helps a learner understand how models balance precision and recall.\", \"city_example\": \"In the project, judging rare incident detection is a useful smart-city example of F1 score.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse F1 score with a related term, so focus on its exact role.\"}', 80, 'medium', 19),
(70, 'imbalance', 'mcq', 'If a learner understands class imbalance, what should they know first? (Curriculum step 20)', '[\"That every model must be perfect\", \"That data never changes\", \"That testing is unnecessary\", \"Describe when one class is much rarer than another\"]', '\"Describe when one class is much rarer than another\"', '{\"concept\": \"Class Imbalance\", \"lesson\": \"Class imbalance occurs when one class appears much more often than another. For example, fraud cases, severe incidents, or rare equipment failures may represent only a small percentage of the data.\\n\\nThis matters because many models and metrics can look good simply by predicting the majority class most of the time. In an imbalanced dataset, accuracy may be high even when the model is poor at detecting the cases you actually care about.\\n\\nHandling imbalance may involve choosing better metrics, adjusting class weights, resampling the data, or designing the decision threshold carefully.\\n\\nA common mistake is assuming imbalance is a data problem that can be ignored if the overall score looks strong. In practice, imbalance often changes how the entire model should be evaluated and tuned.\", \"explanation\": \"Class Imbalance helps a learner understand how models describe when one class is much rarer than another.\", \"city_example\": \"In the project, modelling fraud cases is a useful smart-city example of class imbalance.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse class imbalance with a related term, so focus on its exact role.\"}', 80, 'medium', 20),
(71, 'scaling', 'mcq', 'Which statement best describes feature scaling? (Curriculum step 21)', '[\"Make numeric features comparable in magnitude\", \"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Make numeric features comparable in magnitude\"', '{\"concept\": \"Feature Scaling\", \"lesson\": \"Feature scaling means adjusting numeric variables so they are on comparable ranges. This is important because some algorithms are sensitive to the size of feature values and may let large-scale variables dominate the learning process.\\n\\nFor example, if one feature ranges from 1 to 10 and another from 1 to 10,000, some distance-based or gradient-based methods can be influenced more by the larger numbers simply because of their scale, not because they are more informative.\\n\\nScaling matters for algorithms such as k-nearest neighbours, support vector machines, and many optimisation-based models.\\n\\nA common mistake is assuming scaling is always required for every algorithm. Tree-based models often need it less, while other methods can be strongly affected.\\n\\nAnother common mistake is fitting the scaler before splitting the data, which can introduce leakage.\", \"explanation\": \"Feature Scaling helps a learner understand how models make numeric features comparable in magnitude.\", \"city_example\": \"In the project, using rainfall and income together is a useful smart-city example of feature scaling.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse feature scaling with a related term, so focus on its exact role.\"}', 80, 'medium', 21),
(72, 'normalisation', 'mcq', 'A city team wants to rescaling sensor readings. Which ML idea fits this best? (Curriculum step 22)', '[\"A spreadsheet colour change\", \"Rescale values into a standard range\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Rescale values into a standard range\"', '{\"concept\": \"Normalisation\", \"lesson\": \"Normalisation is a type of feature scaling that transforms values to a common range, often between 0 and 1. This can be useful when you want features to be directly comparable in magnitude.\\n\\nIt is especially helpful for algorithms that depend on distances or when the scale of the inputs varies widely. By keeping features within a bounded range, normalisation can stabilise optimisation and reduce the effect of large raw values.\\n\\nNormalisation is different from standardisation. Normalisation focuses on a fixed range, while standardisation centres features around zero and rescales based on spread.\\n\\nA common mistake is using normalisation without thinking about the data distribution or the model type. The best scaling method depends on the problem, not just on habit.\", \"explanation\": \"Normalisation helps a learner understand how models rescale values into a standard range.\", \"city_example\": \"In the project, rescaling sensor readings is a useful smart-city example of normalisation.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse normalisation with a related term, so focus on its exact role.\"}', 80, 'medium', 22),
(73, 'standardisation', 'mcq', 'Why is standardisation useful in machine learning? (Curriculum step 23)', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"Transform values to mean 0 and standard deviation 1\", \"It only matters for file storage\"]', '\"Transform values to mean 0 and standard deviation 1\"', '{\"concept\": \"Standardisation\", \"lesson\": \"Standardisation transforms a feature so that it has a mean of zero and a standard deviation of one. This keeps the variable centred and puts it on a comparable scale with other features.\\n\\nStandardisation is widely used because many algorithms work better when features have similar distributions and when optimisation is not dominated by variables with large magnitudes.\\n\\nUnlike normalisation, standardisation does not force data into a fixed range. Instead, it expresses values in terms of how far they are from the mean relative to the spread.\\n\\nThis is often useful for models such as logistic regression, support vector machines, and neural networks.\\n\\nA common mistake is assuming standardisation should be applied before the train/test split. The scaler should be fit on the training data only and then applied to the test data to avoid leakage.\", \"explanation\": \"Standardisation helps a learner understand how models transform values to mean 0 and standard deviation 1.\", \"city_example\": \"In the project, preparing mixed-unit features is a useful smart-city example of standardisation.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse standardisation with a related term, so focus on its exact role.\"}', 80, 'medium', 23),
(74, 'imputation', 'mcq', 'Which option is the clearest example of imputation? (Curriculum step 24)', '[\"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\", \"Fill missing values with sensible estimates\"]', '\"Fill missing values with sensible estimates\"', '{\"concept\": \"Imputation\", \"lesson\": \"Imputation is the process of filling in missing values rather than simply discarding incomplete rows. Missing data is common in real-world datasets, and handling it carefully can preserve useful information.\\n\\nSimple imputation methods include replacing missing numeric values with the mean or median, or replacing missing categories with the most common value. More advanced methods try to estimate missing values based on other variables.\\n\\nImputation matters because many machine learning algorithms cannot handle missing values directly. The strategy you choose can influence model quality and bias.\\n\\nA common mistake is to remove every row with missing data without considering how much information is being lost. Another mistake is using a poor imputation strategy that distorts the underlying pattern in the data.\", \"explanation\": \"Imputation helps a learner understand how models fill missing values with sensible estimates.\", \"city_example\": \"In the project, repairing weather gaps is a useful smart-city example of imputation.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse imputation with a related term, so focus on its exact role.\"}', 80, 'medium', 24),
(75, 'one_hot', 'mcq', 'If a learner understands one-hot encoding, what should they know first? (Curriculum step 25)', '[\"Turn categories into binary columns\", \"That every model must be perfect\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Turn categories into binary columns\"', '{\"concept\": \"One-Hot Encoding\", \"lesson\": \"One-hot encoding is a method for turning categorical values into numeric input that a model can use. Each category becomes its own binary feature, indicating whether that category is present or not.\\n\\nFor example, a feature such as transport mode with values like bus, train, and bike can be converted into separate columns. This avoids implying that one category is “larger” or “smaller” than another when no true order exists.\\n\\nOne-hot encoding matters because many models require numeric input but would misinterpret raw text labels or arbitrary numeric codes.\\n\\nA common mistake is using label-style numeric encoding for categories that have no natural order. That can mislead the model into learning relationships that are not actually meaningful.\", \"explanation\": \"One-Hot Encoding helps a learner understand how models turn categories into binary columns.\", \"city_example\": \"In the project, encoding district names is a useful smart-city example of one-hot encoding.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse one-hot encoding with a related term, so focus on its exact role.\"}', 80, 'medium', 25),
(76, 'feature_engineering', 'mcq', 'Which statement best describes feature engineering? (Curriculum step 26)', '[\"It means manually writing every rule by hand\", \"Create better features from raw data\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Create better features from raw data\"', '{\"concept\": \"Feature Engineering\", \"lesson\": \"Feature engineering is the process of creating, transforming, or combining variables so that the model receives more informative input. Rather than only using the raw columns exactly as collected, you design features that better express the underlying problem.\\n\\nExamples include extracting day of week from a date, calculating ratios, grouping rare categories, or turning timestamps into useful behavioural signals.\\n\\nFeature engineering matters because model performance often depends more on the quality of the representation than on the complexity of the algorithm. A well-designed feature can reveal structure that a model would otherwise miss.\\n\\nA common mistake is creating engineered features using information that would not be available at prediction time. That can introduce leakage and make performance look better than it really is.\", \"explanation\": \"Feature Engineering helps a learner understand how models create better features from raw data.\", \"city_example\": \"In the project, extracting hour of day is a useful smart-city example of feature engineering.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse feature engineering with a related term, so focus on its exact role.\"}', 80, 'medium', 26),
(77, 'bias', 'mcq', 'A city team wants to using a very simple demand line. Which ML idea fits this best? (Curriculum step 27)', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"Describe error from oversimplified assumptions\", \"A badge counter only\"]', '\"Describe error from oversimplified assumptions\"', '{\"concept\": \"Bias\", \"lesson\": \"In the bias–variance trade-off, bias refers to error caused by overly simple assumptions in the model. A high-bias model is often too rigid to capture important patterns, which can lead to underfitting.\\n\\nBias matters because every model makes assumptions. Some assumptions are useful simplifications, but if they are too strong, the model may miss real relationships in the data.\\n\\nFor example, a very simple model may ignore nonlinear behaviour or interactions between features. This can keep the model stable, but also too limited.\\n\\nA common mistake is confusing this technical meaning of bias with social or ethical bias. Both are important concepts in machine learning, but they refer to different issues and should be understood separately.\", \"explanation\": \"Bias helps a learner understand how models describe error from oversimplified assumptions.\", \"city_example\": \"In the project, using a very simple demand line is a useful smart-city example of bias.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse bias with a related term, so focus on its exact role.\"}', 80, 'medium', 27),
(78, 'variance', 'mcq', 'Why is variance useful in machine learning? (Curriculum step 28)', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\", \"Describe sensitivity to training-sample changes\"]', '\"Describe sensitivity to training-sample changes\"', '{\"concept\": \"Variance\", \"lesson\": \"In the bias–variance trade-off, variance refers to how sensitive a model is to the specific training data it receives. A high-variance model changes a lot when the training set changes and often captures noise as if it were a meaningful pattern.\\n\\nVariance matters because a model with high variance may perform impressively on the training set but fail to generalise. This is one of the main causes of overfitting.\\n\\nComplex models, weak regularisation, and limited training data can all increase variance. Managing variance often involves simplification, more data, better validation, or stronger constraints.\\n\\nA common mistake is thinking model complexity is always beneficial. More flexibility can help, but it also increases the risk that the model learns unstable, non-transferable patterns.\", \"explanation\": \"Variance helps a learner understand how models describe sensitivity to training-sample changes.\", \"city_example\": \"In the project, seeing an unstable route model is a useful smart-city example of variance.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse variance with a related term, so focus on its exact role.\"}', 80, 'medium', 28),
(79, 'cross_validation', 'mcq', 'Which option is the clearest example of cross-validation? (Curriculum step 29)', '[\"Estimate performance with repeated validation splits\", \"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Estimate performance with repeated validation splits\"', '{\"concept\": \"Cross-Validation\", \"lesson\": \"Cross-validation is an evaluation technique that repeatedly splits the training data into different training and validation portions so that the model can be assessed across multiple runs. This gives a more reliable estimate of performance than relying on a single split alone.\\n\\nIt matters because one train/validation split may be unusually easy or difficult. Cross-validation helps reduce the chance that your judgement of the model depends too heavily on one lucky or unlucky partition.\\n\\nThis is particularly useful when the dataset is not very large, because it allows more efficient use of the available examples.\\n\\nA common mistake is confusing cross-validation with final testing. Cross-validation is often used during model selection and tuning, while the final test set should remain untouched until the end.\", \"explanation\": \"Cross-Validation helps a learner understand how models estimate performance with repeated validation splits.\", \"city_example\": \"In the project, comparing multiple models is a useful smart-city example of cross-validation.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse cross-validation with a related term, so focus on its exact role.\"}', 80, 'medium', 29),
(80, 'leakage', 'mcq', 'If a learner understands data leakage, what should they know first? (Curriculum step 30)', '[\"That every model must be perfect\", \"Use information that would not be available in practice\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Use information that would not be available in practice\"', '{\"concept\": \"Data Leakage\", \"lesson\": \"Data leakage happens when information from outside the proper training process influences the model in a way that would not be available in real deployment. This makes the model appear better during evaluation than it truly is.\\n\\nLeakage can occur in many ways: preprocessing on the full dataset before splitting, using future information to create features, or accidentally including variables that reveal the target.\\n\\nLeakage matters because it creates false confidence. A leaked model may look excellent in development and then fail when deployed.\\n\\nA useful rule is this: if the model is learning from information it would not legitimately have at prediction time, something is wrong.\\n\\nA common mistake is thinking leakage only happens in code. It can also be introduced through feature design, data collection, or careless workflow decisions.\", \"explanation\": \"Data Leakage helps a learner understand how models use information that would not be available in practice.\", \"city_example\": \"In the project, accidentally using future demand is a useful smart-city example of data leakage.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse data leakage with a related term, so focus on its exact role.\"}', 80, 'medium', 30),
(81, 'confusion_matrix', 'mcq', 'Which statement best describes a confusion matrix? (Curriculum step 31)', '[\"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"Break down actual and predicted classes\", \"It guarantees perfect predictions\"]', '\"Break down actual and predicted classes\"', '{\"concept\": \"A Confusion Matrix\", \"lesson\": \"A confusion matrix is a table that compares the model’s predicted classes with the actual classes. It breaks results into categories such as true positives, true negatives, false positives, and false negatives.\\n\\nThis matters because overall accuracy can hide important details about what kinds of mistakes the model is making. A confusion matrix shows exactly where the model succeeds and fails.\\n\\nFor example, in a hazard detection task, false negatives may be much more serious than false positives. The confusion matrix helps reveal whether the model is missing dangerous cases or creating too many false alarms.\\n\\nIt is also the foundation for other metrics such as precision, recall, and F1 score.\\n\\nA common mistake is treating the confusion matrix as just another score. It is better understood as a diagnostic tool that explains the structure of the model’s errors.\", \"explanation\": \"A Confusion Matrix helps a learner understand how models break down actual and predicted classes.\", \"city_example\": \"In the project, reviewing hazard alerts is a useful smart-city example of a confusion matrix.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse a confusion matrix with a related term, so focus on its exact role.\"}', 80, 'medium', 31);
INSERT INTO `tasks` (`task_id`, `ml_topic`, `task_type`, `prompt`, `options`, `correct_answer`, `context`, `reward_points`, `difficulty`, `order_index`) VALUES
(82, 'precision', 'mcq', 'A city team wants to checking inspection flags. Which ML idea fits this best? (Curriculum step 32)', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"A badge counter only\", \"Measure how many predicted positives were correct\"]', '\"Measure how many predicted positives were correct\"', '{\"concept\": \"Precision\", \"lesson\": \"Precision measures how many of the cases predicted as positive were actually positive. In simple terms, it asks: when the model raises an alert, how often is that alert correct?\\n\\nPrecision matters when false positives are costly. For example, if a system flags too many safe situations as risky, it can waste resources, reduce trust, or cause unnecessary disruption.\\n\\nA high-precision model is careful about making positive predictions. That can be valuable in applications like fraud alerts, inspection flags, or targeted interventions where acting on a false alarm has a real cost.\\n\\nHowever, precision alone is not enough. A model can achieve high precision by making very few positive predictions and still miss many real cases.\\n\\nA common mistake is confusing precision with recall. Precision focuses on the correctness of predicted positives, while recall focuses on how many real positives were found.\", \"explanation\": \"Precision helps a learner understand how models measure how many predicted positives were correct.\", \"city_example\": \"In the project, checking inspection flags is a useful smart-city example of precision.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse precision with a related term, so focus on its exact role.\"}', 80, 'medium', 32),
(83, 'recall', 'mcq', 'Why is recall useful in machine learning? (Curriculum step 33)', '[\"Measure how many real positives were found\", \"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\"]', '\"Measure how many real positives were found\"', '{\"concept\": \"Recall\", \"lesson\": \"Recall measures how many of the actual positive cases the model successfully found. In simple terms, it asks: of all the cases that truly matter, how many did the model catch?\\n\\nRecall matters when missing a positive case is costly. In flood warnings, disease screening, or safety alerts, a false negative can be more harmful than a false positive.\\n\\nA high-recall model is good at finding real positives, even if that sometimes means raising extra false alarms. Whether that trade-off is acceptable depends on the application.\\n\\nRecall should usually be interpreted alongside precision. A system that catches nearly everything but generates many false positives may not be practical.\\n\\nA common mistake is thinking recall means the model is generally accurate. It only tells you how well the model finds positives, not how often its positive predictions are correct.\", \"explanation\": \"Recall helps a learner understand how models measure how many real positives were found.\", \"city_example\": \"In the project, checking flood warnings is a useful smart-city example of recall.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse recall with a related term, so focus on its exact role.\"}', 80, 'medium', 33),
(84, 'f1', 'mcq', 'Which option is the clearest example of F1 score? (Curriculum step 34)', '[\"Renaming a folder\", \"Balance precision and recall\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Balance precision and recall\"', '{\"concept\": \"F1 Score\", \"lesson\": \"F1 score combines precision and recall into a single metric by balancing both. It is especially useful when you need a model that both finds important cases and keeps false alarms under control.\\n\\nThe F1 score is most valuable when classes are imbalanced or when using accuracy alone would hide poor behaviour. It rewards systems that achieve a sensible balance rather than excelling in only one dimension.\\n\\nFor example, a fraud model with perfect precision but very low recall would miss most fraud cases. A model with perfect recall but very low precision would overwhelm investigators with false alerts. F1 helps summarise this trade-off.\\n\\nA common mistake is assuming the F1 score replaces all other metrics. It is useful, but you should still examine precision, recall, and the real-world cost of each type of error.\", \"explanation\": \"F1 Score helps a learner understand how models balance precision and recall.\", \"city_example\": \"In the project, judging rare incident detection is a useful smart-city example of F1 score.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse F1 score with a related term, so focus on its exact role.\"}', 80, 'medium', 34),
(85, 'imbalance', 'mcq', 'If a learner understands class imbalance, what should they know first? (Curriculum step 35)', '[\"That every model must be perfect\", \"That data never changes\", \"Describe when one class is much rarer than another\", \"That testing is unnecessary\"]', '\"Describe when one class is much rarer than another\"', '{\"concept\": \"Class Imbalance\", \"lesson\": \"Class imbalance occurs when one class appears much more often than another. For example, fraud cases, severe incidents, or rare equipment failures may represent only a small percentage of the data.\\n\\nThis matters because many models and metrics can look good simply by predicting the majority class most of the time. In an imbalanced dataset, accuracy may be high even when the model is poor at detecting the cases you actually care about.\\n\\nHandling imbalance may involve choosing better metrics, adjusting class weights, resampling the data, or designing the decision threshold carefully.\\n\\nA common mistake is assuming imbalance is a data problem that can be ignored if the overall score looks strong. In practice, imbalance often changes how the entire model should be evaluated and tuned.\", \"explanation\": \"Class Imbalance helps a learner understand how models describe when one class is much rarer than another.\", \"city_example\": \"In the project, modelling fraud cases is a useful smart-city example of class imbalance.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse class imbalance with a related term, so focus on its exact role.\"}', 80, 'medium', 35),
(86, 'scaling', 'mcq', 'Which statement best describes feature scaling? (Curriculum step 36)', '[\"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\", \"Make numeric features comparable in magnitude\"]', '\"Make numeric features comparable in magnitude\"', '{\"concept\": \"Feature Scaling\", \"lesson\": \"Feature scaling means adjusting numeric variables so they are on comparable ranges. This is important because some algorithms are sensitive to the size of feature values and may let large-scale variables dominate the learning process.\\n\\nFor example, if one feature ranges from 1 to 10 and another from 1 to 10,000, some distance-based or gradient-based methods can be influenced more by the larger numbers simply because of their scale, not because they are more informative.\\n\\nScaling matters for algorithms such as k-nearest neighbours, support vector machines, and many optimisation-based models.\\n\\nA common mistake is assuming scaling is always required for every algorithm. Tree-based models often need it less, while other methods can be strongly affected.\\n\\nAnother common mistake is fitting the scaler before splitting the data, which can introduce leakage.\", \"explanation\": \"Feature Scaling helps a learner understand how models make numeric features comparable in magnitude.\", \"city_example\": \"In the project, using rainfall and income together is a useful smart-city example of feature scaling.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse feature scaling with a related term, so focus on its exact role.\"}', 80, 'medium', 36),
(87, 'normalisation', 'mcq', 'A city team wants to rescaling sensor readings. Which ML idea fits this best? (Curriculum step 37)', '[\"Rescale values into a standard range\", \"A spreadsheet colour change\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Rescale values into a standard range\"', '{\"concept\": \"Normalisation\", \"lesson\": \"Normalisation is a type of feature scaling that transforms values to a common range, often between 0 and 1. This can be useful when you want features to be directly comparable in magnitude.\\n\\nIt is especially helpful for algorithms that depend on distances or when the scale of the inputs varies widely. By keeping features within a bounded range, normalisation can stabilise optimisation and reduce the effect of large raw values.\\n\\nNormalisation is different from standardisation. Normalisation focuses on a fixed range, while standardisation centres features around zero and rescales based on spread.\\n\\nA common mistake is using normalisation without thinking about the data distribution or the model type. The best scaling method depends on the problem, not just on habit.\", \"explanation\": \"Normalisation helps a learner understand how models rescale values into a standard range.\", \"city_example\": \"In the project, rescaling sensor readings is a useful smart-city example of normalisation.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse normalisation with a related term, so focus on its exact role.\"}', 80, 'medium', 37),
(88, 'standardisation', 'mcq', 'Why is standardisation useful in machine learning? (Curriculum step 38)', '[\"It removes the need for evaluation\", \"Transform values to mean 0 and standard deviation 1\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\"]', '\"Transform values to mean 0 and standard deviation 1\"', '{\"concept\": \"Standardisation\", \"lesson\": \"Standardisation transforms a feature so that it has a mean of zero and a standard deviation of one. This keeps the variable centred and puts it on a comparable scale with other features.\\n\\nStandardisation is widely used because many algorithms work better when features have similar distributions and when optimisation is not dominated by variables with large magnitudes.\\n\\nUnlike normalisation, standardisation does not force data into a fixed range. Instead, it expresses values in terms of how far they are from the mean relative to the spread.\\n\\nThis is often useful for models such as logistic regression, support vector machines, and neural networks.\\n\\nA common mistake is assuming standardisation should be applied before the train/test split. The scaler should be fit on the training data only and then applied to the test data to avoid leakage.\", \"explanation\": \"Standardisation helps a learner understand how models transform values to mean 0 and standard deviation 1.\", \"city_example\": \"In the project, preparing mixed-unit features is a useful smart-city example of standardisation.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse standardisation with a related term, so focus on its exact role.\"}', 80, 'medium', 38),
(89, 'imputation', 'mcq', 'Which option is the clearest example of imputation? (Curriculum step 39)', '[\"Renaming a folder\", \"Printing a static PDF\", \"Fill missing values with sensible estimates\", \"Changing a chart title\"]', '\"Fill missing values with sensible estimates\"', '{\"concept\": \"Imputation\", \"lesson\": \"Imputation is the process of filling in missing values rather than simply discarding incomplete rows. Missing data is common in real-world datasets, and handling it carefully can preserve useful information.\\n\\nSimple imputation methods include replacing missing numeric values with the mean or median, or replacing missing categories with the most common value. More advanced methods try to estimate missing values based on other variables.\\n\\nImputation matters because many machine learning algorithms cannot handle missing values directly. The strategy you choose can influence model quality and bias.\\n\\nA common mistake is to remove every row with missing data without considering how much information is being lost. Another mistake is using a poor imputation strategy that distorts the underlying pattern in the data.\", \"explanation\": \"Imputation helps a learner understand how models fill missing values with sensible estimates.\", \"city_example\": \"In the project, repairing weather gaps is a useful smart-city example of imputation.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse imputation with a related term, so focus on its exact role.\"}', 80, 'medium', 39),
(90, 'one_hot', 'mcq', 'If a learner understands one-hot encoding, what should they know first? (Curriculum step 40)', '[\"That every model must be perfect\", \"That data never changes\", \"That testing is unnecessary\", \"Turn categories into binary columns\"]', '\"Turn categories into binary columns\"', '{\"concept\": \"One-Hot Encoding\", \"lesson\": \"One-hot encoding is a method for turning categorical values into numeric input that a model can use. Each category becomes its own binary feature, indicating whether that category is present or not.\\n\\nFor example, a feature such as transport mode with values like bus, train, and bike can be converted into separate columns. This avoids implying that one category is “larger” or “smaller” than another when no true order exists.\\n\\nOne-hot encoding matters because many models require numeric input but would misinterpret raw text labels or arbitrary numeric codes.\\n\\nA common mistake is using label-style numeric encoding for categories that have no natural order. That can mislead the model into learning relationships that are not actually meaningful.\", \"explanation\": \"One-Hot Encoding helps a learner understand how models turn categories into binary columns.\", \"city_example\": \"In the project, encoding district names is a useful smart-city example of one-hot encoding.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse one-hot encoding with a related term, so focus on its exact role.\"}', 80, 'medium', 40),
(91, 'feature_engineering', 'mcq', 'Which statement best describes feature engineering? (Curriculum step 41)', '[\"Create better features from raw data\", \"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Create better features from raw data\"', '{\"concept\": \"Feature Engineering\", \"lesson\": \"Feature engineering is the process of creating, transforming, or combining variables so that the model receives more informative input. Rather than only using the raw columns exactly as collected, you design features that better express the underlying problem.\\n\\nExamples include extracting day of week from a date, calculating ratios, grouping rare categories, or turning timestamps into useful behavioural signals.\\n\\nFeature engineering matters because model performance often depends more on the quality of the representation than on the complexity of the algorithm. A well-designed feature can reveal structure that a model would otherwise miss.\\n\\nA common mistake is creating engineered features using information that would not be available at prediction time. That can introduce leakage and make performance look better than it really is.\", \"explanation\": \"Feature Engineering helps a learner understand how models create better features from raw data.\", \"city_example\": \"In the project, extracting hour of day is a useful smart-city example of feature engineering.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse feature engineering with a related term, so focus on its exact role.\"}', 80, 'medium', 41),
(92, 'bias', 'mcq', 'A city team wants to using a very simple demand line. Which ML idea fits this best? (Curriculum step 42)', '[\"A spreadsheet colour change\", \"Describe error from oversimplified assumptions\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Describe error from oversimplified assumptions\"', '{\"concept\": \"Bias\", \"lesson\": \"In the bias–variance trade-off, bias refers to error caused by overly simple assumptions in the model. A high-bias model is often too rigid to capture important patterns, which can lead to underfitting.\\n\\nBias matters because every model makes assumptions. Some assumptions are useful simplifications, but if they are too strong, the model may miss real relationships in the data.\\n\\nFor example, a very simple model may ignore nonlinear behaviour or interactions between features. This can keep the model stable, but also too limited.\\n\\nA common mistake is confusing this technical meaning of bias with social or ethical bias. Both are important concepts in machine learning, but they refer to different issues and should be understood separately.\", \"explanation\": \"Bias helps a learner understand how models describe error from oversimplified assumptions.\", \"city_example\": \"In the project, using a very simple demand line is a useful smart-city example of bias.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse bias with a related term, so focus on its exact role.\"}', 80, 'medium', 42),
(93, 'variance', 'mcq', 'Why is variance useful in machine learning? (Curriculum step 43)', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"Describe sensitivity to training-sample changes\", \"It only matters for file storage\"]', '\"Describe sensitivity to training-sample changes\"', '{\"concept\": \"Variance\", \"lesson\": \"In the bias–variance trade-off, variance refers to how sensitive a model is to the specific training data it receives. A high-variance model changes a lot when the training set changes and often captures noise as if it were a meaningful pattern.\\n\\nVariance matters because a model with high variance may perform impressively on the training set but fail to generalise. This is one of the main causes of overfitting.\\n\\nComplex models, weak regularisation, and limited training data can all increase variance. Managing variance often involves simplification, more data, better validation, or stronger constraints.\\n\\nA common mistake is thinking model complexity is always beneficial. More flexibility can help, but it also increases the risk that the model learns unstable, non-transferable patterns.\", \"explanation\": \"Variance helps a learner understand how models describe sensitivity to training-sample changes.\", \"city_example\": \"In the project, seeing an unstable route model is a useful smart-city example of variance.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse variance with a related term, so focus on its exact role.\"}', 80, 'medium', 43),
(94, 'cross_validation', 'mcq', 'Which option is the clearest example of cross-validation? (Curriculum step 44)', '[\"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\", \"Estimate performance with repeated validation splits\"]', '\"Estimate performance with repeated validation splits\"', '{\"concept\": \"Cross-Validation\", \"lesson\": \"Cross-validation is an evaluation technique that repeatedly splits the training data into different training and validation portions so that the model can be assessed across multiple runs. This gives a more reliable estimate of performance than relying on a single split alone.\\n\\nIt matters because one train/validation split may be unusually easy or difficult. Cross-validation helps reduce the chance that your judgement of the model depends too heavily on one lucky or unlucky partition.\\n\\nThis is particularly useful when the dataset is not very large, because it allows more efficient use of the available examples.\\n\\nA common mistake is confusing cross-validation with final testing. Cross-validation is often used during model selection and tuning, while the final test set should remain untouched until the end.\", \"explanation\": \"Cross-Validation helps a learner understand how models estimate performance with repeated validation splits.\", \"city_example\": \"In the project, comparing multiple models is a useful smart-city example of cross-validation.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse cross-validation with a related term, so focus on its exact role.\"}', 80, 'medium', 44),
(95, 'leakage', 'mcq', 'If a learner understands data leakage, what should they know first? (Curriculum step 45)', '[\"Use information that would not be available in practice\", \"That every model must be perfect\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Use information that would not be available in practice\"', '{\"concept\": \"Data Leakage\", \"lesson\": \"Data leakage happens when information from outside the proper training process influences the model in a way that would not be available in real deployment. This makes the model appear better during evaluation than it truly is.\\n\\nLeakage can occur in many ways: preprocessing on the full dataset before splitting, using future information to create features, or accidentally including variables that reveal the target.\\n\\nLeakage matters because it creates false confidence. A leaked model may look excellent in development and then fail when deployed.\\n\\nA useful rule is this: if the model is learning from information it would not legitimately have at prediction time, something is wrong.\\n\\nA common mistake is thinking leakage only happens in code. It can also be introduced through feature design, data collection, or careless workflow decisions.\", \"explanation\": \"Data Leakage helps a learner understand how models use information that would not be available in practice.\", \"city_example\": \"In the project, accidentally using future demand is a useful smart-city example of data leakage.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse data leakage with a related term, so focus on its exact role.\"}', 80, 'medium', 45),
(96, 'confusion_matrix', 'mcq', 'Which statement best describes a confusion matrix? (Curriculum step 46)', '[\"It means manually writing every rule by hand\", \"Break down actual and predicted classes\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Break down actual and predicted classes\"', '{\"concept\": \"A Confusion Matrix\", \"lesson\": \"A confusion matrix is a table that compares the model’s predicted classes with the actual classes. It breaks results into categories such as true positives, true negatives, false positives, and false negatives.\\n\\nThis matters because overall accuracy can hide important details about what kinds of mistakes the model is making. A confusion matrix shows exactly where the model succeeds and fails.\\n\\nFor example, in a hazard detection task, false negatives may be much more serious than false positives. The confusion matrix helps reveal whether the model is missing dangerous cases or creating too many false alarms.\\n\\nIt is also the foundation for other metrics such as precision, recall, and F1 score.\\n\\nA common mistake is treating the confusion matrix as just another score. It is better understood as a diagnostic tool that explains the structure of the model’s errors.\", \"explanation\": \"A Confusion Matrix helps a learner understand how models break down actual and predicted classes.\", \"city_example\": \"In the project, reviewing hazard alerts is a useful smart-city example of a confusion matrix.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse a confusion matrix with a related term, so focus on its exact role.\"}', 80, 'medium', 46),
(97, 'precision', 'mcq', 'A city team wants to checking inspection flags. Which ML idea fits this best? (Curriculum step 47)', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"Measure how many predicted positives were correct\", \"A badge counter only\"]', '\"Measure how many predicted positives were correct\"', '{\"concept\": \"Precision\", \"lesson\": \"Precision measures how many of the cases predicted as positive were actually positive. In simple terms, it asks: when the model raises an alert, how often is that alert correct?\\n\\nPrecision matters when false positives are costly. For example, if a system flags too many safe situations as risky, it can waste resources, reduce trust, or cause unnecessary disruption.\\n\\nA high-precision model is careful about making positive predictions. That can be valuable in applications like fraud alerts, inspection flags, or targeted interventions where acting on a false alarm has a real cost.\\n\\nHowever, precision alone is not enough. A model can achieve high precision by making very few positive predictions and still miss many real cases.\\n\\nA common mistake is confusing precision with recall. Precision focuses on the correctness of predicted positives, while recall focuses on how many real positives were found.\", \"explanation\": \"Precision helps a learner understand how models measure how many predicted positives were correct.\", \"city_example\": \"In the project, checking inspection flags is a useful smart-city example of precision.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse precision with a related term, so focus on its exact role.\"}', 80, 'medium', 47),
(98, 'recall', 'mcq', 'Why is recall useful in machine learning? (Curriculum step 48)', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\", \"Measure how many real positives were found\"]', '\"Measure how many real positives were found\"', '{\"concept\": \"Recall\", \"lesson\": \"Recall measures how many of the actual positive cases the model successfully found. In simple terms, it asks: of all the cases that truly matter, how many did the model catch?\\n\\nRecall matters when missing a positive case is costly. In flood warnings, disease screening, or safety alerts, a false negative can be more harmful than a false positive.\\n\\nA high-recall model is good at finding real positives, even if that sometimes means raising extra false alarms. Whether that trade-off is acceptable depends on the application.\\n\\nRecall should usually be interpreted alongside precision. A system that catches nearly everything but generates many false positives may not be practical.\\n\\nA common mistake is thinking recall means the model is generally accurate. It only tells you how well the model finds positives, not how often its positive predictions are correct.\", \"explanation\": \"Recall helps a learner understand how models measure how many real positives were found.\", \"city_example\": \"In the project, checking flood warnings is a useful smart-city example of recall.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse recall with a related term, so focus on its exact role.\"}', 80, 'medium', 48),
(99, 'f1', 'mcq', 'Which option is the clearest example of F1 score? (Curriculum step 49)', '[\"Balance precision and recall\", \"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Balance precision and recall\"', '{\"concept\": \"F1 Score\", \"lesson\": \"F1 score combines precision and recall into a single metric by balancing both. It is especially useful when you need a model that both finds important cases and keeps false alarms under control.\\n\\nThe F1 score is most valuable when classes are imbalanced or when using accuracy alone would hide poor behaviour. It rewards systems that achieve a sensible balance rather than excelling in only one dimension.\\n\\nFor example, a fraud model with perfect precision but very low recall would miss most fraud cases. A model with perfect recall but very low precision would overwhelm investigators with false alerts. F1 helps summarise this trade-off.\\n\\nA common mistake is assuming the F1 score replaces all other metrics. It is useful, but you should still examine precision, recall, and the real-world cost of each type of error.\", \"explanation\": \"F1 Score helps a learner understand how models balance precision and recall.\", \"city_example\": \"In the project, judging rare incident detection is a useful smart-city example of F1 score.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse F1 score with a related term, so focus on its exact role.\"}', 80, 'medium', 49),
(100, 'imbalance', 'mcq', 'If a learner understands class imbalance, what should they know first? (Curriculum step 50)', '[\"That every model must be perfect\", \"Describe when one class is much rarer than another\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Describe when one class is much rarer than another\"', '{\"concept\": \"Class Imbalance\", \"lesson\": \"Class imbalance occurs when one class appears much more often than another. For example, fraud cases, severe incidents, or rare equipment failures may represent only a small percentage of the data.\\n\\nThis matters because many models and metrics can look good simply by predicting the majority class most of the time. In an imbalanced dataset, accuracy may be high even when the model is poor at detecting the cases you actually care about.\\n\\nHandling imbalance may involve choosing better metrics, adjusting class weights, resampling the data, or designing the decision threshold carefully.\\n\\nA common mistake is assuming imbalance is a data problem that can be ignored if the overall score looks strong. In practice, imbalance often changes how the entire model should be evaluated and tuned.\", \"explanation\": \"Class Imbalance helps a learner understand how models describe when one class is much rarer than another.\", \"city_example\": \"In the project, modelling fraud cases is a useful smart-city example of class imbalance.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse class imbalance with a related term, so focus on its exact role.\"}', 80, 'medium', 50),
(101, 'regularisation', 'mcq', 'Which statement best describes regularisation?', '[\"Reduce overfitting by discouraging overly complex solutions\", \"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Reduce overfitting by discouraging overly complex solutions\"', '{\"concept\": \"Regularisation\", \"lesson\": \"Regularisation is a technique used to reduce overfitting by discouraging models from becoming unnecessarily complex. It adds a constraint or penalty that pushes the model toward simpler solutions unless the extra complexity is genuinely useful.\\n\\nThis matters because very flexible models can fit noise in the training data. Regularisation helps the model focus on stronger, more general patterns.\\n\\nIn practice, regularisation can improve test performance, stability, and robustness. It is especially important in settings with many features or limited data.\\n\\nA common mistake is thinking regularisation exists to make the model weaker. Its purpose is not to reduce learning, but to improve generalisation by preventing the model from chasing unhelpful detail.\", \"explanation\": \"Regularisation helps a learner understand how models reduce overfitting by discouraging overly complex solutions.\", \"city_example\": \"In the project, controlling a forecast model is a useful smart-city example of regularisation.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse regularisation with a related term, so focus on its exact role.\"}', 120, 'hard', 1),
(102, 'hyperparameters', 'mcq', 'A city team wants to choosing learning rate. Which ML idea fits this best?', '[\"A spreadsheet colour change\", \"Set training choices before fitting\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Set training choices before fitting\"', '{\"concept\": \"Hyperparameters\", \"lesson\": \"Hyperparameters are settings chosen before or during training that control how the learning process works. They are not learned from the data in the same way as model parameters. Examples include learning rate, tree depth, regularisation strength, and number of neighbours.\\n\\nHyperparameters matter because they strongly influence performance, training stability, speed, and risk of overfitting. Even a good algorithm can perform badly if its hyperparameters are poorly chosen.\\n\\nSelecting hyperparameters usually involves experimentation, validation, and comparison rather than guesswork. This is one reason careful evaluation is essential.\\n\\nA common mistake is confusing hyperparameters with parameters. Parameters are learned by the model from the data; hyperparameters are set by the developer or tuning process.\", \"explanation\": \"Hyperparameters helps a learner understand how models set training choices before fitting.\", \"city_example\": \"In the project, choosing learning rate is a useful smart-city example of hyperparameters.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse hyperparameters with a related term, so focus on its exact role.\"}', 120, 'hard', 2),
(103, 'gradient_descent', 'mcq', 'Why is gradient descent useful in machine learning?', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"Reduce loss step by step\", \"It only matters for file storage\"]', '\"Reduce loss step by step\"', '{\"concept\": \"Gradient Descent\", \"lesson\": \"Gradient descent is an optimisation method used to reduce a model’s loss by making small adjustments to its parameters in the direction that most decreases error. It is widely used in machine learning, especially for models trained iteratively.\\n\\nThe key idea is that the model checks how the loss changes with respect to each parameter and then moves step by step toward a better solution. The size of each step is often controlled by the learning rate.\\n\\nGradient descent matters because many models cannot be solved analytically and must be trained through optimisation.\\n\\nA common mistake is thinking gradient descent always finds the perfect answer quickly. In practice, its behaviour depends on the loss surface, the learning rate, the starting point, and the quality of the data.\", \"explanation\": \"Gradient Descent helps a learner understand how models reduce loss step by step.\", \"city_example\": \"In the project, optimising a demand model is a useful smart-city example of gradient descent.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse gradient descent with a related term, so focus on its exact role.\"}', 120, 'hard', 3),
(104, 'loss', 'mcq', 'Which option is the clearest example of a loss function?', '[\"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\", \"Measure how wrong the model is\"]', '\"Measure how wrong the model is\"', '{\"concept\": \"A Loss Function\", \"lesson\": \"Loss is the numerical measure of how wrong a model’s predictions are during training. Lower loss means the predictions are closer to the desired outcome according to the chosen objective function.\\n\\nThe model trains by trying to reduce this loss. Different tasks use different loss functions because different kinds of mistakes should be measured in different ways.\\n\\nLoss matters because it is the signal that guides learning. If the loss function is poorly matched to the task, the model may optimise the wrong behaviour.\\n\\nA common mistake is treating loss and accuracy as the same thing. Accuracy is an evaluation metric based on correct predictions, while loss is a training objective that usually gives more detailed feedback to the optimisation process.\", \"explanation\": \"A Loss Function helps a learner understand how models measure how wrong the model is.\", \"city_example\": \"In the project, measuring forecast error is a useful smart-city example of a loss function.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse a loss function with a related term, so focus on its exact role.\"}', 120, 'hard', 4),
(105, 'pipelines', 'mcq', 'If a learner understands pipelines, what should they know first?', '[\"Keep preprocessing and prediction steps consistent\", \"That every model must be perfect\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Keep preprocessing and prediction steps consistent\"', '{\"concept\": \"Pipelines\", \"lesson\": \"A machine learning pipeline is a structured workflow that links together preprocessing, feature transformation, model training, and sometimes prediction in a consistent sequence. Pipelines help ensure that the same steps are applied in the same order every time.\\n\\nPipelines matter because machine learning projects often fail through inconsistency rather than algorithm choice. A pipeline reduces the chance of forgetting a step, applying different transformations to train and test data, or introducing leakage by accident.\\n\\nThey also make experiments easier to reproduce and maintain, which is important for both coursework and real systems.\\n\\nA common mistake is performing preprocessing manually in separate pieces of code and losing track of what was fit where. A pipeline makes the workflow explicit and safer.\", \"explanation\": \"Pipelines helps a learner understand how models keep preprocessing and prediction steps consistent.\", \"city_example\": \"In the project, handling live service requests is a useful smart-city example of pipelines.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse pipelines with a related term, so focus on its exact role.\"}', 120, 'hard', 5),
(106, 'deployment', 'mcq', 'Which statement best describes deployment?', '[\"It means manually writing every rule by hand\", \"Put a trained model into real use\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Put a trained model into real use\"', '{\"concept\": \"Deployment\", \"lesson\": \"Deployment is the stage where a trained model is put into a real application so that it can make predictions on live or operational data. This is where machine learning moves from experiment to actual use.\\n\\nDeployment matters because a model that works in development is not automatically ready for the real world. You must consider latency, reliability, monitoring, fairness, input validation, retraining plans, and what happens when the data changes.\\n\\nA deployed model is part of a wider system, not an isolated notebook result. It must be maintained, observed, and aligned with the context in which people rely on it.\\n\\nA common mistake is treating deployment as “done” once the model is uploaded somewhere. In reality, deployment is the beginning of operational responsibility.\", \"explanation\": \"Deployment helps a learner understand how models put a trained model into real use.\", \"city_example\": \"In the project, running predictions in a traffic dashboard is a useful smart-city example of deployment.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse deployment with a related term, so focus on its exact role.\"}', 120, 'hard', 6),
(107, 'feature_importance', 'mcq', 'A city team wants to reviewing rainfall and demand. Which ML idea fits this best?', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"Show which inputs influence predictions most\", \"A badge counter only\"]', '\"Show which inputs influence predictions most\"', '{\"concept\": \"Feature Importance\", \"lesson\": \"Feature importance refers to techniques that estimate how influential each input variable is in a model’s predictions. It helps answer the question: which features matter most to the model?\\n\\nThis matters for interpretation, debugging, trust, and feature selection. If a model relies heavily on a surprising or problematic feature, that may reveal a design issue, leakage, or bias.\\n\\nHowever, feature importance must be interpreted carefully. Different methods measure importance differently, and high importance does not automatically mean a feature causes the outcome.\\n\\nA common mistake is assuming that important features are always the ones humans expected. Sometimes that is useful discovery; other times it is a sign that the model is exploiting a shortcut.\", \"explanation\": \"Feature Importance helps a learner understand how models show which inputs influence predictions most.\", \"city_example\": \"In the project, reviewing rainfall and demand is a useful smart-city example of feature importance.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse feature importance with a related term, so focus on its exact role.\"}', 120, 'hard', 7),
(108, 'ensembles', 'mcq', 'Why is ensembling useful in machine learning?', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\", \"Combine multiple models for robustness\"]', '\"Combine multiple models for robustness\"', '{\"concept\": \"Ensembling\", \"lesson\": \"An ensemble combines the predictions of multiple models in order to achieve better performance, stability, or robustness than a single model alone. The central idea is that a group of models can often compensate for one another’s weaknesses.\\n\\nEnsembles matter because different models may capture different aspects of the data. By aggregating them, you can often reduce variance, improve accuracy, and make predictions less sensitive to one model’s errors.\\n\\nExamples include bagging, random forests, and boosting.\\n\\nA common mistake is assuming ensembles are always the best choice. They can improve performance, but they may also increase complexity, reduce interpretability, and make deployment harder.\", \"explanation\": \"Ensembling helps a learner understand how models combine multiple models for robustness.\", \"city_example\": \"In the project, building a committee forecast is a useful smart-city example of ensembling.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse ensembling with a related term, so focus on its exact role.\"}', 120, 'hard', 8),
(109, 'random_forests', 'mcq', 'Which option is the clearest example of random forests?', '[\"Average many trees to reduce overfitting\", \"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Average many trees to reduce overfitting\"', '{\"concept\": \"Random Forests\", \"lesson\": \"Random forests are an ensemble method built from many decision trees. Each tree is trained on a different sample of the data and usually considers only a subset of features at each split. The final prediction is produced by combining the outputs of all the trees.\\n\\nThis matters because a single decision tree can be unstable and prone to overfitting. By averaging many trees, random forests usually become more robust and generalise better.\\n\\nRandom forests are often strong baseline models because they handle mixed feature types well and require relatively little preprocessing.\\n\\nA common mistake is thinking they are just one large tree. They are actually a coordinated collection of many trees designed to reduce variance and improve stability.\", \"explanation\": \"Random Forests helps a learner understand how models average many trees to reduce overfitting.\", \"city_example\": \"In the project, improving risk scoring is a useful smart-city example of random forests.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse random forests with a related term, so focus on its exact role.\"}', 120, 'hard', 9);
INSERT INTO `tasks` (`task_id`, `ml_topic`, `task_type`, `prompt`, `options`, `correct_answer`, `context`, `reward_points`, `difficulty`, `order_index`) VALUES
(110, 'boosting', 'mcq', 'If a learner understands boosting, what should they know first?', '[\"That every model must be perfect\", \"Focus later models on earlier mistakes\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Focus later models on earlier mistakes\"', '{\"concept\": \"Boosting\", \"lesson\": \"Boosting is an ensemble technique where models are trained sequentially, with later models focusing more on the errors made by earlier ones. Instead of averaging many independent models, boosting builds a strong predictor by gradually correcting mistakes.\\n\\nThis matters because boosting can achieve very strong performance, especially when weak learners on their own are only moderately effective.\\n\\nThe general idea is to pay more attention to difficult cases over time so that the final system improves where earlier models struggled.\\n\\nA common mistake is assuming boosting simply means “use more models”. The key feature is the sequence and the emphasis on previous errors, not just the number of learners.\", \"explanation\": \"Boosting helps a learner understand how models focus later models on earlier mistakes.\", \"city_example\": \"In the project, refining difficult cases is a useful smart-city example of boosting.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse boosting with a related term, so focus on its exact role.\"}', 120, 'hard', 10),
(111, 'fairness', 'mcq', 'Which statement best describes fairness?', '[\"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"Matter when decisions affect different communities\", \"It guarantees perfect predictions\"]', '\"Matter when decisions affect different communities\"', '{\"concept\": \"Fairness\", \"lesson\": \"Fairness in machine learning is the idea that model decisions should not create unjust or harmful differences across people or groups, especially in high-impact contexts such as healthcare, policing, education, or access to services.\\n\\nFairness matters because a model can be technically accurate while still producing harmful outcomes if the training data reflects past inequalities, the labels are biased, or performance differs sharply between groups.\\n\\nThinking about fairness requires more than checking one score. You must consider who is affected, how errors are distributed, what data was used, and whether the system supports responsible decision-making.\\n\\nA common mistake is treating fairness as optional because it seems separate from technical work. In real machine learning systems, fairness is part of good design, evaluation, and deployment.\", \"explanation\": \"Fairness helps a learner understand how models matter when decisions affect different communities.\", \"city_example\": \"In the project, prioritising services responsibly is a useful smart-city example of fairness.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse fairness with a related term, so focus on its exact role.\"}', 120, 'hard', 11),
(112, 'transparency', 'mcq', 'A city team wants to supporting public trust. Which ML idea fits this best?', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"A badge counter only\", \"Help explain how data and models are used\"]', '\"Help explain how data and models are used\"', '{\"concept\": \"Transparency\", \"lesson\": \"Transparency means making it possible to understand how a machine learning system was built, what data it uses, what limitations it has, and how its outputs should be interpreted. Transparency supports trust, accountability, and safer use.\\n\\nThis matters because users, stakeholders, and affected communities may need to know why a model exists, what it can and cannot do, and how decisions are being supported.\\n\\nTransparency does not always require exposing every mathematical detail. It often means providing clear documentation, honest limitations, understandable explanations, and a traceable workflow.\\n\\nA common mistake is assuming transparency only matters for highly complex models. Even simple systems should be documented and explained if people are expected to rely on them.\", \"explanation\": \"Transparency helps a learner understand how models help explain how data and models are used.\", \"city_example\": \"In the project, supporting public trust is a useful smart-city example of transparency.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse transparency with a related term, so focus on its exact role.\"}', 120, 'hard', 12),
(113, 'data_drift', 'mcq', 'Why is data drift useful in machine learning?', '[\"Describe changing input distributions after deployment\", \"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\"]', '\"Describe changing input distributions after deployment\"', '{\"concept\": \"Data Drift\", \"lesson\": \"Data drift happens when the distribution or characteristics of incoming data change over time compared with the data used to train the model. When this happens, a model that once performed well can gradually become less reliable.\\n\\nDrift matters because the world does not stay still. Travel patterns, user behaviour, weather conditions, economic factors, and reporting practices can all shift. A model trained on old patterns may then make weaker predictions.\\n\\nThis is why deployed systems need monitoring, not just initial testing. If input data changes, performance should be checked and retraining may be needed.\\n\\nA common mistake is assuming a model that worked during development will continue working indefinitely without review.\", \"explanation\": \"Data Drift helps a learner understand how models describe changing input distributions after deployment.\", \"city_example\": \"In the project, noticing sensor pattern shifts is a useful smart-city example of data drift.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse data drift with a related term, so focus on its exact role.\"}', 120, 'hard', 13),
(114, 'latency', 'mcq', 'Which option is the clearest example of latency?', '[\"Renaming a folder\", \"Measure how quickly predictions are returned\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Measure how quickly predictions are returned\"', '{\"concept\": \"Latency\", \"lesson\": \"Latency is the time it takes for a system to return a prediction after receiving an input. In many real-world applications, speed is part of quality, not just convenience.\\n\\nLatency matters because some decisions must happen quickly. A routing tool, traffic signal support system, or live safety alert may become less useful if predictions arrive too slowly.\\n\\nThe best model is not always the one with the highest offline score. If it is too slow or too expensive to serve, it may be impractical.\\n\\nA common mistake is evaluating models only on accuracy and ignoring response time. In deployment, a slightly simpler model can be the better choice if it is fast enough for the real context.\", \"explanation\": \"Latency helps a learner understand how models measure how quickly predictions are returned.\", \"city_example\": \"In the project, serving real-time traffic help is a useful smart-city example of latency.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse latency with a related term, so focus on its exact role.\"}', 120, 'hard', 14),
(115, 'cost_of_errors', 'mcq', 'If a learner understands cost of errors, what should they know first?', '[\"That every model must be perfect\", \"That data never changes\", \"Reflect that different mistakes cause different harm\", \"That testing is unnecessary\"]', '\"Reflect that different mistakes cause different harm\"', '{\"concept\": \"Cost Of Errors\", \"lesson\": \"The cost of errors refers to the idea that different mistakes made by a model can have different real-world consequences. A false positive and a false negative are not always equally harmful.\\n\\nThis matters because machine learning evaluation should reflect the actual problem. In some contexts, missing a dangerous case is far worse than raising a false alarm. In others, repeated false alarms waste time and reduce trust.\\n\\nThinking about error cost helps you choose suitable metrics, decision thresholds, and system behaviour. It connects technical evaluation with practical impact.\\n\\nA common mistake is treating every incorrect prediction as equally bad just because both count as “wrong” in a simple score.\", \"explanation\": \"Cost Of Errors helps a learner understand how models reflect that different mistakes cause different harm.\", \"city_example\": \"In the project, comparing missed hazards and false alarms is a useful smart-city example of cost of errors.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse cost of errors with a related term, so focus on its exact role.\"}', 120, 'hard', 15),
(116, 'regularisation', 'mcq', 'Which statement best describes regularisation? (Curriculum step 16)', '[\"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\", \"Reduce overfitting by discouraging overly complex solutions\"]', '\"Reduce overfitting by discouraging overly complex solutions\"', '{\"concept\": \"Regularisation\", \"lesson\": \"Regularisation is a technique used to reduce overfitting by discouraging models from becoming unnecessarily complex. It adds a constraint or penalty that pushes the model toward simpler solutions unless the extra complexity is genuinely useful.\\n\\nThis matters because very flexible models can fit noise in the training data. Regularisation helps the model focus on stronger, more general patterns.\\n\\nIn practice, regularisation can improve test performance, stability, and robustness. It is especially important in settings with many features or limited data.\\n\\nA common mistake is thinking regularisation exists to make the model weaker. Its purpose is not to reduce learning, but to improve generalisation by preventing the model from chasing unhelpful detail.\", \"explanation\": \"Regularisation helps a learner understand how models reduce overfitting by discouraging overly complex solutions.\", \"city_example\": \"In the project, controlling a forecast model is a useful smart-city example of regularisation.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse regularisation with a related term, so focus on its exact role.\"}', 120, 'hard', 16),
(117, 'hyperparameters', 'mcq', 'A city team wants to choosing learning rate. Which ML idea fits this best? (Curriculum step 17)', '[\"Set training choices before fitting\", \"A spreadsheet colour change\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Set training choices before fitting\"', '{\"concept\": \"Hyperparameters\", \"lesson\": \"Hyperparameters are settings chosen before or during training that control how the learning process works. They are not learned from the data in the same way as model parameters. Examples include learning rate, tree depth, regularisation strength, and number of neighbours.\\n\\nHyperparameters matter because they strongly influence performance, training stability, speed, and risk of overfitting. Even a good algorithm can perform badly if its hyperparameters are poorly chosen.\\n\\nSelecting hyperparameters usually involves experimentation, validation, and comparison rather than guesswork. This is one reason careful evaluation is essential.\\n\\nA common mistake is confusing hyperparameters with parameters. Parameters are learned by the model from the data; hyperparameters are set by the developer or tuning process.\", \"explanation\": \"Hyperparameters helps a learner understand how models set training choices before fitting.\", \"city_example\": \"In the project, choosing learning rate is a useful smart-city example of hyperparameters.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse hyperparameters with a related term, so focus on its exact role.\"}', 120, 'hard', 17),
(118, 'gradient_descent', 'mcq', 'Why is gradient descent useful in machine learning? (Curriculum step 18)', '[\"It removes the need for evaluation\", \"Reduce loss step by step\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\"]', '\"Reduce loss step by step\"', '{\"concept\": \"Gradient Descent\", \"lesson\": \"Gradient descent is an optimisation method used to reduce a model’s loss by making small adjustments to its parameters in the direction that most decreases error. It is widely used in machine learning, especially for models trained iteratively.\\n\\nThe key idea is that the model checks how the loss changes with respect to each parameter and then moves step by step toward a better solution. The size of each step is often controlled by the learning rate.\\n\\nGradient descent matters because many models cannot be solved analytically and must be trained through optimisation.\\n\\nA common mistake is thinking gradient descent always finds the perfect answer quickly. In practice, its behaviour depends on the loss surface, the learning rate, the starting point, and the quality of the data.\", \"explanation\": \"Gradient Descent helps a learner understand how models reduce loss step by step.\", \"city_example\": \"In the project, optimising a demand model is a useful smart-city example of gradient descent.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse gradient descent with a related term, so focus on its exact role.\"}', 120, 'hard', 18),
(119, 'loss', 'mcq', 'Which option is the clearest example of a loss function? (Curriculum step 19)', '[\"Renaming a folder\", \"Printing a static PDF\", \"Measure how wrong the model is\", \"Changing a chart title\"]', '\"Measure how wrong the model is\"', '{\"concept\": \"A Loss Function\", \"lesson\": \"Loss is the numerical measure of how wrong a model’s predictions are during training. Lower loss means the predictions are closer to the desired outcome according to the chosen objective function.\\n\\nThe model trains by trying to reduce this loss. Different tasks use different loss functions because different kinds of mistakes should be measured in different ways.\\n\\nLoss matters because it is the signal that guides learning. If the loss function is poorly matched to the task, the model may optimise the wrong behaviour.\\n\\nA common mistake is treating loss and accuracy as the same thing. Accuracy is an evaluation metric based on correct predictions, while loss is a training objective that usually gives more detailed feedback to the optimisation process.\", \"explanation\": \"A Loss Function helps a learner understand how models measure how wrong the model is.\", \"city_example\": \"In the project, measuring forecast error is a useful smart-city example of a loss function.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse a loss function with a related term, so focus on its exact role.\"}', 120, 'hard', 19),
(120, 'pipelines', 'mcq', 'If a learner understands pipelines, what should they know first? (Curriculum step 20)', '[\"That every model must be perfect\", \"That data never changes\", \"That testing is unnecessary\", \"Keep preprocessing and prediction steps consistent\"]', '\"Keep preprocessing and prediction steps consistent\"', '{\"concept\": \"Pipelines\", \"lesson\": \"A machine learning pipeline is a structured workflow that links together preprocessing, feature transformation, model training, and sometimes prediction in a consistent sequence. Pipelines help ensure that the same steps are applied in the same order every time.\\n\\nPipelines matter because machine learning projects often fail through inconsistency rather than algorithm choice. A pipeline reduces the chance of forgetting a step, applying different transformations to train and test data, or introducing leakage by accident.\\n\\nThey also make experiments easier to reproduce and maintain, which is important for both coursework and real systems.\\n\\nA common mistake is performing preprocessing manually in separate pieces of code and losing track of what was fit where. A pipeline makes the workflow explicit and safer.\", \"explanation\": \"Pipelines helps a learner understand how models keep preprocessing and prediction steps consistent.\", \"city_example\": \"In the project, handling live service requests is a useful smart-city example of pipelines.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse pipelines with a related term, so focus on its exact role.\"}', 120, 'hard', 20),
(121, 'deployment', 'mcq', 'Which statement best describes deployment? (Curriculum step 21)', '[\"Put a trained model into real use\", \"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Put a trained model into real use\"', '{\"concept\": \"Deployment\", \"lesson\": \"Deployment is the stage where a trained model is put into a real application so that it can make predictions on live or operational data. This is where machine learning moves from experiment to actual use.\\n\\nDeployment matters because a model that works in development is not automatically ready for the real world. You must consider latency, reliability, monitoring, fairness, input validation, retraining plans, and what happens when the data changes.\\n\\nA deployed model is part of a wider system, not an isolated notebook result. It must be maintained, observed, and aligned with the context in which people rely on it.\\n\\nA common mistake is treating deployment as “done” once the model is uploaded somewhere. In reality, deployment is the beginning of operational responsibility.\", \"explanation\": \"Deployment helps a learner understand how models put a trained model into real use.\", \"city_example\": \"In the project, running predictions in a traffic dashboard is a useful smart-city example of deployment.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse deployment with a related term, so focus on its exact role.\"}', 120, 'hard', 21),
(122, 'feature_importance', 'mcq', 'A city team wants to reviewing rainfall and demand. Which ML idea fits this best? (Curriculum step 22)', '[\"A spreadsheet colour change\", \"Show which inputs influence predictions most\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Show which inputs influence predictions most\"', '{\"concept\": \"Feature Importance\", \"lesson\": \"Feature importance refers to techniques that estimate how influential each input variable is in a model’s predictions. It helps answer the question: which features matter most to the model?\\n\\nThis matters for interpretation, debugging, trust, and feature selection. If a model relies heavily on a surprising or problematic feature, that may reveal a design issue, leakage, or bias.\\n\\nHowever, feature importance must be interpreted carefully. Different methods measure importance differently, and high importance does not automatically mean a feature causes the outcome.\\n\\nA common mistake is assuming that important features are always the ones humans expected. Sometimes that is useful discovery; other times it is a sign that the model is exploiting a shortcut.\", \"explanation\": \"Feature Importance helps a learner understand how models show which inputs influence predictions most.\", \"city_example\": \"In the project, reviewing rainfall and demand is a useful smart-city example of feature importance.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse feature importance with a related term, so focus on its exact role.\"}', 120, 'hard', 22),
(123, 'ensembles', 'mcq', 'Why is ensembling useful in machine learning? (Curriculum step 23)', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"Combine multiple models for robustness\", \"It only matters for file storage\"]', '\"Combine multiple models for robustness\"', '{\"concept\": \"Ensembling\", \"lesson\": \"An ensemble combines the predictions of multiple models in order to achieve better performance, stability, or robustness than a single model alone. The central idea is that a group of models can often compensate for one another’s weaknesses.\\n\\nEnsembles matter because different models may capture different aspects of the data. By aggregating them, you can often reduce variance, improve accuracy, and make predictions less sensitive to one model’s errors.\\n\\nExamples include bagging, random forests, and boosting.\\n\\nA common mistake is assuming ensembles are always the best choice. They can improve performance, but they may also increase complexity, reduce interpretability, and make deployment harder.\", \"explanation\": \"Ensembling helps a learner understand how models combine multiple models for robustness.\", \"city_example\": \"In the project, building a committee forecast is a useful smart-city example of ensembling.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse ensembling with a related term, so focus on its exact role.\"}', 120, 'hard', 23),
(124, 'random_forests', 'mcq', 'Which option is the clearest example of random forests? (Curriculum step 24)', '[\"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\", \"Average many trees to reduce overfitting\"]', '\"Average many trees to reduce overfitting\"', '{\"concept\": \"Random Forests\", \"lesson\": \"Random forests are an ensemble method built from many decision trees. Each tree is trained on a different sample of the data and usually considers only a subset of features at each split. The final prediction is produced by combining the outputs of all the trees.\\n\\nThis matters because a single decision tree can be unstable and prone to overfitting. By averaging many trees, random forests usually become more robust and generalise better.\\n\\nRandom forests are often strong baseline models because they handle mixed feature types well and require relatively little preprocessing.\\n\\nA common mistake is thinking they are just one large tree. They are actually a coordinated collection of many trees designed to reduce variance and improve stability.\", \"explanation\": \"Random Forests helps a learner understand how models average many trees to reduce overfitting.\", \"city_example\": \"In the project, improving risk scoring is a useful smart-city example of random forests.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse random forests with a related term, so focus on its exact role.\"}', 120, 'hard', 24),
(125, 'boosting', 'mcq', 'If a learner understands boosting, what should they know first? (Curriculum step 25)', '[\"Focus later models on earlier mistakes\", \"That every model must be perfect\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Focus later models on earlier mistakes\"', '{\"concept\": \"Boosting\", \"lesson\": \"Boosting is an ensemble technique where models are trained sequentially, with later models focusing more on the errors made by earlier ones. Instead of averaging many independent models, boosting builds a strong predictor by gradually correcting mistakes.\\n\\nThis matters because boosting can achieve very strong performance, especially when weak learners on their own are only moderately effective.\\n\\nThe general idea is to pay more attention to difficult cases over time so that the final system improves where earlier models struggled.\\n\\nA common mistake is assuming boosting simply means “use more models”. The key feature is the sequence and the emphasis on previous errors, not just the number of learners.\", \"explanation\": \"Boosting helps a learner understand how models focus later models on earlier mistakes.\", \"city_example\": \"In the project, refining difficult cases is a useful smart-city example of boosting.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse boosting with a related term, so focus on its exact role.\"}', 120, 'hard', 25),
(126, 'fairness', 'mcq', 'Which statement best describes fairness? (Curriculum step 26)', '[\"It means manually writing every rule by hand\", \"Matter when decisions affect different communities\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\"]', '\"Matter when decisions affect different communities\"', '{\"concept\": \"Fairness\", \"lesson\": \"Fairness in machine learning is the idea that model decisions should not create unjust or harmful differences across people or groups, especially in high-impact contexts such as healthcare, policing, education, or access to services.\\n\\nFairness matters because a model can be technically accurate while still producing harmful outcomes if the training data reflects past inequalities, the labels are biased, or performance differs sharply between groups.\\n\\nThinking about fairness requires more than checking one score. You must consider who is affected, how errors are distributed, what data was used, and whether the system supports responsible decision-making.\\n\\nA common mistake is treating fairness as optional because it seems separate from technical work. In real machine learning systems, fairness is part of good design, evaluation, and deployment.\", \"explanation\": \"Fairness helps a learner understand how models matter when decisions affect different communities.\", \"city_example\": \"In the project, prioritising services responsibly is a useful smart-city example of fairness.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse fairness with a related term, so focus on its exact role.\"}', 120, 'hard', 26),
(127, 'transparency', 'mcq', 'A city team wants to supporting public trust. Which ML idea fits this best? (Curriculum step 27)', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"Help explain how data and models are used\", \"A badge counter only\"]', '\"Help explain how data and models are used\"', '{\"concept\": \"Transparency\", \"lesson\": \"Transparency means making it possible to understand how a machine learning system was built, what data it uses, what limitations it has, and how its outputs should be interpreted. Transparency supports trust, accountability, and safer use.\\n\\nThis matters because users, stakeholders, and affected communities may need to know why a model exists, what it can and cannot do, and how decisions are being supported.\\n\\nTransparency does not always require exposing every mathematical detail. It often means providing clear documentation, honest limitations, understandable explanations, and a traceable workflow.\\n\\nA common mistake is assuming transparency only matters for highly complex models. Even simple systems should be documented and explained if people are expected to rely on them.\", \"explanation\": \"Transparency helps a learner understand how models help explain how data and models are used.\", \"city_example\": \"In the project, supporting public trust is a useful smart-city example of transparency.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse transparency with a related term, so focus on its exact role.\"}', 120, 'hard', 27),
(128, 'data_drift', 'mcq', 'Why is data drift useful in machine learning? (Curriculum step 28)', '[\"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\", \"Describe changing input distributions after deployment\"]', '\"Describe changing input distributions after deployment\"', '{\"concept\": \"Data Drift\", \"lesson\": \"Data drift happens when the distribution or characteristics of incoming data change over time compared with the data used to train the model. When this happens, a model that once performed well can gradually become less reliable.\\n\\nDrift matters because the world does not stay still. Travel patterns, user behaviour, weather conditions, economic factors, and reporting practices can all shift. A model trained on old patterns may then make weaker predictions.\\n\\nThis is why deployed systems need monitoring, not just initial testing. If input data changes, performance should be checked and retraining may be needed.\\n\\nA common mistake is assuming a model that worked during development will continue working indefinitely without review.\", \"explanation\": \"Data Drift helps a learner understand how models describe changing input distributions after deployment.\", \"city_example\": \"In the project, noticing sensor pattern shifts is a useful smart-city example of data drift.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse data drift with a related term, so focus on its exact role.\"}', 120, 'hard', 28),
(129, 'latency', 'mcq', 'Which option is the clearest example of latency? (Curriculum step 29)', '[\"Measure how quickly predictions are returned\", \"Renaming a folder\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Measure how quickly predictions are returned\"', '{\"concept\": \"Latency\", \"lesson\": \"Latency is the time it takes for a system to return a prediction after receiving an input. In many real-world applications, speed is part of quality, not just convenience.\\n\\nLatency matters because some decisions must happen quickly. A routing tool, traffic signal support system, or live safety alert may become less useful if predictions arrive too slowly.\\n\\nThe best model is not always the one with the highest offline score. If it is too slow or too expensive to serve, it may be impractical.\\n\\nA common mistake is evaluating models only on accuracy and ignoring response time. In deployment, a slightly simpler model can be the better choice if it is fast enough for the real context.\", \"explanation\": \"Latency helps a learner understand how models measure how quickly predictions are returned.\", \"city_example\": \"In the project, serving real-time traffic help is a useful smart-city example of latency.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse latency with a related term, so focus on its exact role.\"}', 120, 'hard', 29),
(130, 'cost_of_errors', 'mcq', 'If a learner understands cost of errors, what should they know first? (Curriculum step 30)', '[\"That every model must be perfect\", \"Reflect that different mistakes cause different harm\", \"That data never changes\", \"That testing is unnecessary\"]', '\"Reflect that different mistakes cause different harm\"', '{\"concept\": \"Cost Of Errors\", \"lesson\": \"The cost of errors refers to the idea that different mistakes made by a model can have different real-world consequences. A false positive and a false negative are not always equally harmful.\\n\\nThis matters because machine learning evaluation should reflect the actual problem. In some contexts, missing a dangerous case is far worse than raising a false alarm. In others, repeated false alarms waste time and reduce trust.\\n\\nThinking about error cost helps you choose suitable metrics, decision thresholds, and system behaviour. It connects technical evaluation with practical impact.\\n\\nA common mistake is treating every incorrect prediction as equally bad just because both count as “wrong” in a simple score.\", \"explanation\": \"Cost Of Errors helps a learner understand how models reflect that different mistakes cause different harm.\", \"city_example\": \"In the project, comparing missed hazards and false alarms is a useful smart-city example of cost of errors.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse cost of errors with a related term, so focus on its exact role.\"}', 120, 'hard', 30),
(131, 'regularisation', 'mcq', 'Which statement best describes regularisation? (Curriculum step 31)', '[\"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"Reduce overfitting by discouraging overly complex solutions\", \"It guarantees perfect predictions\"]', '\"Reduce overfitting by discouraging overly complex solutions\"', '{\"concept\": \"Regularisation\", \"lesson\": \"Regularisation is a technique used to reduce overfitting by discouraging models from becoming unnecessarily complex. It adds a constraint or penalty that pushes the model toward simpler solutions unless the extra complexity is genuinely useful.\\n\\nThis matters because very flexible models can fit noise in the training data. Regularisation helps the model focus on stronger, more general patterns.\\n\\nIn practice, regularisation can improve test performance, stability, and robustness. It is especially important in settings with many features or limited data.\\n\\nA common mistake is thinking regularisation exists to make the model weaker. Its purpose is not to reduce learning, but to improve generalisation by preventing the model from chasing unhelpful detail.\", \"explanation\": \"Regularisation helps a learner understand how models reduce overfitting by discouraging overly complex solutions.\", \"city_example\": \"In the project, controlling a forecast model is a useful smart-city example of regularisation.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse regularisation with a related term, so focus on its exact role.\"}', 120, 'hard', 31),
(132, 'hyperparameters', 'mcq', 'A city team wants to choosing learning rate. Which ML idea fits this best? (Curriculum step 32)', '[\"A spreadsheet colour change\", \"A manual guess with no data\", \"A badge counter only\", \"Set training choices before fitting\"]', '\"Set training choices before fitting\"', '{\"concept\": \"Hyperparameters\", \"lesson\": \"Hyperparameters are settings chosen before or during training that control how the learning process works. They are not learned from the data in the same way as model parameters. Examples include learning rate, tree depth, regularisation strength, and number of neighbours.\\n\\nHyperparameters matter because they strongly influence performance, training stability, speed, and risk of overfitting. Even a good algorithm can perform badly if its hyperparameters are poorly chosen.\\n\\nSelecting hyperparameters usually involves experimentation, validation, and comparison rather than guesswork. This is one reason careful evaluation is essential.\\n\\nA common mistake is confusing hyperparameters with parameters. Parameters are learned by the model from the data; hyperparameters are set by the developer or tuning process.\", \"explanation\": \"Hyperparameters helps a learner understand how models set training choices before fitting.\", \"city_example\": \"In the project, choosing learning rate is a useful smart-city example of hyperparameters.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse hyperparameters with a related term, so focus on its exact role.\"}', 120, 'hard', 32),
(133, 'gradient_descent', 'mcq', 'Why is gradient descent useful in machine learning? (Curriculum step 33)', '[\"Reduce loss step by step\", \"It removes the need for evaluation\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\"]', '\"Reduce loss step by step\"', '{\"concept\": \"Gradient Descent\", \"lesson\": \"Gradient descent is an optimisation method used to reduce a model’s loss by making small adjustments to its parameters in the direction that most decreases error. It is widely used in machine learning, especially for models trained iteratively.\\n\\nThe key idea is that the model checks how the loss changes with respect to each parameter and then moves step by step toward a better solution. The size of each step is often controlled by the learning rate.\\n\\nGradient descent matters because many models cannot be solved analytically and must be trained through optimisation.\\n\\nA common mistake is thinking gradient descent always finds the perfect answer quickly. In practice, its behaviour depends on the loss surface, the learning rate, the starting point, and the quality of the data.\", \"explanation\": \"Gradient Descent helps a learner understand how models reduce loss step by step.\", \"city_example\": \"In the project, optimising a demand model is a useful smart-city example of gradient descent.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse gradient descent with a related term, so focus on its exact role.\"}', 120, 'hard', 33),
(134, 'loss', 'mcq', 'Which option is the clearest example of a loss function? (Curriculum step 34)', '[\"Renaming a folder\", \"Measure how wrong the model is\", \"Printing a static PDF\", \"Changing a chart title\"]', '\"Measure how wrong the model is\"', '{\"concept\": \"A Loss Function\", \"lesson\": \"Loss is the numerical measure of how wrong a model’s predictions are during training. Lower loss means the predictions are closer to the desired outcome according to the chosen objective function.\\n\\nThe model trains by trying to reduce this loss. Different tasks use different loss functions because different kinds of mistakes should be measured in different ways.\\n\\nLoss matters because it is the signal that guides learning. If the loss function is poorly matched to the task, the model may optimise the wrong behaviour.\\n\\nA common mistake is treating loss and accuracy as the same thing. Accuracy is an evaluation metric based on correct predictions, while loss is a training objective that usually gives more detailed feedback to the optimisation process.\", \"explanation\": \"A Loss Function helps a learner understand how models measure how wrong the model is.\", \"city_example\": \"In the project, measuring forecast error is a useful smart-city example of a loss function.\", \"hint\": \"Pick the option that reflects the concept itself.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse a loss function with a related term, so focus on its exact role.\"}', 120, 'hard', 34),
(135, 'pipelines', 'mcq', 'If a learner understands pipelines, what should they know first? (Curriculum step 35)', '[\"That every model must be perfect\", \"That data never changes\", \"Keep preprocessing and prediction steps consistent\", \"That testing is unnecessary\"]', '\"Keep preprocessing and prediction steps consistent\"', '{\"concept\": \"Pipelines\", \"lesson\": \"A machine learning pipeline is a structured workflow that links together preprocessing, feature transformation, model training, and sometimes prediction in a consistent sequence. Pipelines help ensure that the same steps are applied in the same order every time.\\n\\nPipelines matter because machine learning projects often fail through inconsistency rather than algorithm choice. A pipeline reduces the chance of forgetting a step, applying different transformations to train and test data, or introducing leakage by accident.\\n\\nThey also make experiments easier to reproduce and maintain, which is important for both coursework and real systems.\\n\\nA common mistake is performing preprocessing manually in separate pieces of code and losing track of what was fit where. A pipeline makes the workflow explicit and safer.\", \"explanation\": \"Pipelines helps a learner understand how models keep preprocessing and prediction steps consistent.\", \"city_example\": \"In the project, handling live service requests is a useful smart-city example of pipelines.\", \"hint\": \"Choose the foundational statement.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse pipelines with a related term, so focus on its exact role.\"}', 120, 'hard', 35),
(136, 'deployment', 'mcq', 'Which statement best describes deployment? (Curriculum step 36)', '[\"It means manually writing every rule by hand\", \"It is mainly about deleting labels\", \"It guarantees perfect predictions\", \"Put a trained model into real use\"]', '\"Put a trained model into real use\"', '{\"concept\": \"Deployment\", \"lesson\": \"Deployment is the stage where a trained model is put into a real application so that it can make predictions on live or operational data. This is where machine learning moves from experiment to actual use.\\n\\nDeployment matters because a model that works in development is not automatically ready for the real world. You must consider latency, reliability, monitoring, fairness, input validation, retraining plans, and what happens when the data changes.\\n\\nA deployed model is part of a wider system, not an isolated notebook result. It must be maintained, observed, and aligned with the context in which people rely on it.\\n\\nA common mistake is treating deployment as “done” once the model is uploaded somewhere. In reality, deployment is the beginning of operational responsibility.\", \"explanation\": \"Deployment helps a learner understand how models put a trained model into real use.\", \"city_example\": \"In the project, running predictions in a traffic dashboard is a useful smart-city example of deployment.\", \"hint\": \"Focus on the core definition.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse deployment with a related term, so focus on its exact role.\"}', 120, 'hard', 36),
(137, 'feature_importance', 'mcq', 'A city team wants to reviewing rainfall and demand. Which ML idea fits this best? (Curriculum step 37)', '[\"Show which inputs influence predictions most\", \"A spreadsheet colour change\", \"A manual guess with no data\", \"A badge counter only\"]', '\"Show which inputs influence predictions most\"', '{\"concept\": \"Feature Importance\", \"lesson\": \"Feature importance refers to techniques that estimate how influential each input variable is in a model’s predictions. It helps answer the question: which features matter most to the model?\\n\\nThis matters for interpretation, debugging, trust, and feature selection. If a model relies heavily on a surprising or problematic feature, that may reveal a design issue, leakage, or bias.\\n\\nHowever, feature importance must be interpreted carefully. Different methods measure importance differently, and high importance does not automatically mean a feature causes the outcome.\\n\\nA common mistake is assuming that important features are always the ones humans expected. Sometimes that is useful discovery; other times it is a sign that the model is exploiting a shortcut.\", \"explanation\": \"Feature Importance helps a learner understand how models show which inputs influence predictions most.\", \"city_example\": \"In the project, reviewing rainfall and demand is a useful smart-city example of feature importance.\", \"hint\": \"Match the concept to the city example.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse feature importance with a related term, so focus on its exact role.\"}', 120, 'hard', 37),
(138, 'ensembles', 'mcq', 'Why is ensembling useful in machine learning? (Curriculum step 38)', '[\"It removes the need for evaluation\", \"Combine multiple models for robustness\", \"It makes every dataset unbiased automatically\", \"It only matters for file storage\"]', '\"Combine multiple models for robustness\"', '{\"concept\": \"Ensembling\", \"lesson\": \"An ensemble combines the predictions of multiple models in order to achieve better performance, stability, or robustness than a single model alone. The central idea is that a group of models can often compensate for one another’s weaknesses.\\n\\nEnsembles matter because different models may capture different aspects of the data. By aggregating them, you can often reduce variance, improve accuracy, and make predictions less sensitive to one model’s errors.\\n\\nExamples include bagging, random forests, and boosting.\\n\\nA common mistake is assuming ensembles are always the best choice. They can improve performance, but they may also increase complexity, reduce interpretability, and make deployment harder.\", \"explanation\": \"Ensembling helps a learner understand how models combine multiple models for robustness.\", \"city_example\": \"In the project, building a committee forecast is a useful smart-city example of ensembling.\", \"hint\": \"Think about why the concept helps learning or prediction.\", \"why_it_matters\": \"This concept supports stronger decisions and helps learners build transferable machine-learning understanding.\", \"common_mistake\": \"Learners often confuse ensembling with a related term, so focus on its exact role.\"}', 120, 'hard', 38);
INSERT INTO `tasks` (`task_id`, `ml_topic`, `task_type`, `prompt`, `options`, `correct_answer`, `context`, `reward_points`, `difficulty`, `order_index`) VALUES
